function resolveInstructionAssetUrl(url, fallbackFileName) {
  const base =
    typeof PUBLIC_BASE_URL === "string"
      ? PUBLIC_BASE_URL.replace(/\/$/, "")
      : "";
  const candidate = (() => {
    if (typeof url === "string" && url.trim()) {
      return url.trim();
    }
    if (fallbackFileName) {
      return `/assets/instructions/${fallbackFileName}`;
    }
    return null;
  })();
  if (!candidate) return null;
  if (/^https?:\/\//i.test(candidate)) {
    return candidate;
  }
  const pathPart = candidate.startsWith("/")
    ? candidate
    : `/assets/instructions/${candidate}`;
  if (base) {
    return `${base}${pathPart}`;
  }
  return pathPart;
}

// Line Client จะถูกสร้างเมื่อต้องการใช้งานจริง (ไม่สร้างตั้งแต่เริ่มต้น)
let lineClient = null;

// ฟังก์ชันสำหรับสร้าง Line Client เมื่อต้องการใช้งาน
function createLineClient(channelAccessToken, channelSecret) {
  if (!channelAccessToken || !channelSecret) {
    throw new Error(
      "Channel Access Token และ Channel Secret จำเป็นสำหรับการใช้งาน Line Bot",
    );
  }

  const lineConfig = {
    channelAccessToken,
    channelSecret,
  };

  return new line.Client(lineConfig);
}

const LINE_BOT_CREDENTIAL_CACHE_TTL_MS = 5 * 60 * 1000;
const lineBotCredentialCache = new Map();

async function getLineBotCredentials(botId) {
  const id = typeof botId === "string" ? botId.trim() : botId ? String(botId) : "";
  if (!ObjectId.isValid(id)) return null;

  const cached = lineBotCredentialCache.get(id);
  if (cached && Date.now() - cached.fetchedAt < LINE_BOT_CREDENTIAL_CACHE_TTL_MS) {
    return cached.credentials;
  }

  const client = await connectDB();
  const db = client.db("chatbot");
  const bot = await db.collection("line_bots").findOne(
    { _id: new ObjectId(id) },
    { projection: { channelAccessToken: 1, channelSecret: 1 } },
  );

  const credentials =
    bot && bot.channelAccessToken && bot.channelSecret
      ? {
        channelAccessToken: bot.channelAccessToken,
        channelSecret: bot.channelSecret,
      }
      : null;

  lineBotCredentialCache.set(id, { fetchedAt: Date.now(), credentials });
  return credentials;
}

async function getLineClientForContext(botId = null) {
  const credentials = await getLineBotCredentials(botId);
  if (credentials) {
    return createLineClient(
      credentials.channelAccessToken,
      credentials.channelSecret,
    );
  }

  if (lineClient) {
    return lineClient;
  }

  if (LINE_CHANNEL_ACCESS_TOKEN && LINE_CHANNEL_SECRET) {
    lineClient = createLineClient(LINE_CHANNEL_ACCESS_TOKEN, LINE_CHANNEL_SECRET);
    return lineClient;
  }

  return null;
}

function normalizeChatPlatform(platform, fallback = "line") {
  if (typeof platform !== "string") return fallback;
  const normalized = platform.trim().toLowerCase();
  return SUPPORTED_CHAT_PLATFORMS.has(normalized) ? normalized : fallback;
}

function getBotCollectionName(platform, fallbackCollection = "line_bots") {
  const normalized = normalizeChatPlatform(platform);
  return BOT_COLLECTION_BY_PLATFORM[normalized] || fallbackCollection;
}

function normalizeRuntimeCacheId(value, fallback = "default") {
  if (value instanceof ObjectId) {
    return value.toString();
  }
  if (typeof value === "string" && value.trim()) {
    return value.trim();
  }
  if (value && typeof value === "object" && value._id) {
    return normalizeRuntimeCacheId(value._id, fallback);
  }
  if (value === null || typeof value === "undefined") {
    return fallback;
  }
  const normalized = String(value).trim();
  return normalized || fallback;
}

function buildBotRuntimeCacheKey(platform, botId = null) {
  const normalizedPlatform = normalizeChatPlatform(platform, "line");
  const normalizedBotId = normalizeRuntimeCacheId(botId, "default");
  return `${normalizedPlatform}:${normalizedBotId}`;
}

function normalizeInstructionSelectionCacheValue(selectedInstructions = []) {
  const normalizedSelections = normalizeLatestOnlyInstructionSelections(
    Array.isArray(selectedInstructions) ? selectedInstructions : [],
  );
  return JSON.stringify(normalizedSelections);
}

function normalizeAssetSelectionCacheKey(selectedCollectionIds = null) {
  if (
    !Array.isArray(selectedCollectionIds) ||
    selectedCollectionIds.length === 0
  ) {
    return "__all__";
  }

  const normalizedIds = Array.from(
    new Set(
      selectedCollectionIds
        .map((entry) => normalizeRuntimeCacheId(entry, ""))
        .filter(Boolean),
    ),
  ).sort();

  return normalizedIds.length > 0 ? normalizedIds.join("|") : "__all__";
}

const runtimeBotSnapshotCache = new Map();
const runtimePromptBaseCache = new Map();
const runtimeAssetsTextCache = new Map();
const runtimeAssetsMapCache = new Map();
const runtimeOpenAIKeyCache = new Map();
const runtimeBotAiConfigCache = new Map();

function clearCacheMapEntriesByPrefix(cacheMap, prefix) {
  if (!cacheMap || !prefix) return;
  for (const key of cacheMap.keys()) {
    if (typeof key === "string" && key.startsWith(prefix)) {
      cacheMap.delete(key);
    }
  }
}

function invalidateInstructionPromptCaches() {
  runtimePromptBaseCache.clear();
}

function invalidateAssetRuntimeCaches() {
  runtimeAssetsTextCache.clear();
  runtimeAssetsMapCache.clear();
  invalidateInstructionPromptCaches();
}

function invalidateOpenAIKeyRuntimeCaches() {
  runtimeOpenAIKeyCache.clear();
}

function invalidateBotRuntimeCaches(platform = null, botId = null) {
  if (!platform || !botId) {
    runtimeBotSnapshotCache.clear();
    runtimeBotAiConfigCache.clear();
    invalidateOpenAIKeyRuntimeCaches();
    invalidateInstructionPromptCaches();
    return;
  }

  const runtimeKey = buildBotRuntimeCacheKey(platform, botId);
  runtimeBotSnapshotCache.delete(runtimeKey);
  runtimeBotAiConfigCache.delete(runtimeKey);
  runtimeOpenAIKeyCache.delete(runtimeKey);
  clearCacheMapEntriesByPrefix(runtimePromptBaseCache, `${runtimeKey}::`);
}

function invalidateAllRuntimeCaches() {
  invalidateBotRuntimeCaches();
  invalidateAssetRuntimeCaches();
}

