async function getBotRuntimeSnapshot(botId, platform) {
  if (!botId) return null;

  const runtimeKey = buildBotRuntimeCacheKey(platform, botId);
  if (runtimeBotSnapshotCache.has(runtimeKey)) {
    return runtimeBotSnapshotCache.get(runtimeKey);
  }

  try {
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection(getBotCollectionName(platform));
    const normalizedBotId = normalizeRuntimeCacheId(botId, "");
    const query = ObjectId.isValid(normalizedBotId)
      ? { _id: new ObjectId(normalizedBotId) }
      : { _id: normalizedBotId };

    const bot = await coll.findOne(query, {
      projection: {
        selectedInstructions: 1,
        selectedImageCollections: 1,
        aiConfig: 1,
        openaiApiKeyId: 1,
      },
    });

    const snapshot = bot
      ? {
        selectedInstructions: Array.isArray(bot.selectedInstructions)
          ? bot.selectedInstructions
          : [],
        selectedImageCollections: Array.isArray(bot.selectedImageCollections)
          ? bot.selectedImageCollections
          : [],
        aiConfig: normalizeAiConfig(bot.aiConfig || {}),
        openaiApiKeyId: bot.openaiApiKeyId || null,
      }
      : null;

    runtimeBotSnapshotCache.set(runtimeKey, snapshot);
    return snapshot;
  } catch (error) {
    console.error("[RuntimeCache] ไม่สามารถดึง bot runtime snapshot ได้:", error);
    return null;
  }
}

function getPlatformLabel(platform) {
  const normalized = normalizeChatPlatform(platform);
  if (normalized === "facebook") return "Facebook";
  if (normalized === "line") return "LINE";
  if (normalized === "instagram") return "Instagram";
  if (normalized === "whatsapp") return "WhatsApp";
  return String(platform || "Unknown");
}

function getBotDisplayName(platform, bot = {}) {
  const normalized = normalizeChatPlatform(platform);
  if (normalized === "line") {
    return bot.name || bot.displayName || bot.botName || null;
  }
  if (normalized === "facebook") {
    return bot.pageName || bot.name || null;
  }
  if (normalized === "instagram") {
    return (
      bot.name ||
      bot.instagramUsername ||
      bot.username ||
      bot.instagramUserId ||
      bot.igUserId ||
      null
    );
  }
  if (normalized === "whatsapp") {
    return bot.name || bot.displayName || bot.phoneNumber || bot.phoneNumberId || null;
  }
  return bot.name || null;
}

function resolveInstagramSenderId(bot = {}) {
  return (
    bot.instagramBusinessAccountId ||
    bot.instagramUserId ||
    bot.igUserId ||
    bot.pageId ||
    null
  );
}

function resolveWhatsAppPhoneNumberId(bot = {}) {
  return bot.phoneNumberId || bot.whatsappPhoneNumberId || null;
}

function resolveMetaAccessToken(bot = {}) {
  return (
    bot.accessToken ||
    bot.facebookAccessToken ||
    bot.instagramAccessToken ||
    bot.whatsappAccessToken ||
    null
  );
}

function chunkTextByLength(value, maxLength) {
  const text = typeof value === "string" ? value : String(value || "");
  if (!text.trim()) return [];
  const chunks = [];
  for (let i = 0; i < text.length; i += maxLength) {
    const chunk = text.slice(i, i + maxLength).trim();
    if (chunk) chunks.push(chunk);
  }
  return chunks;
}

async function findBotById(db, platform, botId) {
  if (!db || !botId) return null;
  const collection = getBotCollectionName(platform);
  const coll = db.collection(collection);
  if (ObjectId.isValid(botId)) {
    return coll.findOne({ _id: new ObjectId(botId) });
  }
  return coll.findOne({ _id: botId });
}

