// === ฟังก์ชันโมเดลเล็ก: วิเคราะห์ Flow และข้อมูลที่ขาด (ฟังก์ชันใหม่ไม่มีการประกาศ openai ซ้ำซ้อน)
// (ลบฟังก์ชัน analyzeFlowGPT4oMini)
// ... existing code ...
// (ลบฟังก์ชัน analyzeImageWithAnotherModel)
// ... existing code ...

// ------------------------
// ระบบคิวข้อความ (ประมวลผลแบบต่อคิวทีละรอบต่อผู้ใช้/เพจ)
// ------------------------
const processedIds = new Set();
const userQueues = {}; // { queueKey: { userId, messages: [], timer: null, context: {}, isProcessing: false, flushRequested: false, flushDelayMs: null } }
const USER_QUEUE_IDLE_CLEANUP_MS = 5 * 60 * 1000;
const USER_QUEUE_SWEEP_INTERVAL_MS = 60 * 1000;

function touchQueue(queue) {
  if (queue) {
    queue.lastTouchedAt = Date.now();
  }
}

function isQueueDisposable(queue) {
  return (
    !!queue &&
    Array.isArray(queue.messages) &&
    queue.messages.length === 0 &&
    !queue.timer &&
    !queue.isProcessing &&
    !queue.flushRequested
  );
}

function tryDisposeQueue(queueKey) {
  const queue = userQueues[queueKey];
  if (!isQueueDisposable(queue)) return false;
  delete userQueues[queueKey];
  return true;
}

const userQueueSweepTimer = setInterval(() => {
  const now = Date.now();
  for (const [queueKey, queue] of Object.entries(userQueues)) {
    if (!isQueueDisposable(queue)) continue;
    const lastTouchedAt = Number(queue?.lastTouchedAt || 0);
    if (!lastTouchedAt || now - lastTouchedAt >= USER_QUEUE_IDLE_CLEANUP_MS) {
      delete userQueues[queueKey];
    }
  }
}, USER_QUEUE_SWEEP_INTERVAL_MS);
userQueueSweepTimer.unref?.();

function buildQueueKey(userId, options = {}) {
  if (options.queueKey) {
    return options.queueKey;
  }
  const idPart =
    typeof userId === "string" ? userId : String(userId || "unknown");
  const botType = options.botType || options.platform || null;
  const rawBotId = options.botId || options.lineBotId || null;
  if (botType || rawBotId) {
    const botId = rawBotId || "default";
    return `${botType || "bot"}:${botId}:${idPart}`;
  }
  return idPart;
}

function mergeQueueContext(existingContext = {}, newContext = {}) {
  const merged = { ...existingContext, ...newContext };
  if (!merged.botId && merged.lineBotId) {
    merged.botId = merged.lineBotId;
  }
  if (!merged.platform) {
    merged.platform = merged.botType || "line";
  }
  if (!merged.botType) {
    merged.botType = merged.platform || "line";
  }
  if (!merged.platform && merged.botType === "line") {
    merged.platform = "line";
  }
  return merged;
}

function clearQueueTimer(queue) {
  if (!queue || !queue.timer) {
    return;
  }
  clearTimeout(queue.timer);
  queue.timer = null;
  touchQueue(queue);
}

function scheduleQueueFlush(queueKey, delayMs = 0) {
  const queue = userQueues[queueKey];
  if (!queue) return;

  const normalizedDelayMs =
    Number.isFinite(delayMs) && delayMs >= 0 ? Math.floor(delayMs) : 0;
  const delaySeconds = (normalizedDelayMs / 1000).toFixed(2).replace(/\.00$/, "");

  clearQueueTimer(queue);
  queue.timer = setTimeout(() => {
    const currentQueue = userQueues[queueKey];
    if (!currentQueue) return;
    const queueUserId = currentQueue.userId || "unknown";
    logHotPathDebug(
      `[LOG] ครบเวลา delay (${delaySeconds} วินาที) เริ่มประมวลผลคิวสำหรับผู้ใช้: ${queueUserId} (queueKey: ${queueKey})`,
    );
    flushQueue(queueKey).catch((err) => {
      console.error(
        `[LOG] เกิดข้อผิดพลาดระหว่างประมวลผลคิวสำหรับผู้ใช้ ${queueUserId} (queueKey: ${queueKey}):`,
        err,
      );
    });
  }, normalizedDelayMs);
  touchQueue(queue);
}

function requestQueueFlush(queueKey, delayMs = 0) {
  const queue = userQueues[queueKey];
  if (!queue) return;

  const normalizedDelayMs =
    Number.isFinite(delayMs) && delayMs >= 0 ? Math.floor(delayMs) : 0;
  queue.flushRequested = true;
  if (queue.flushDelayMs === null || normalizedDelayMs < queue.flushDelayMs) {
    queue.flushDelayMs = normalizedDelayMs;
  }

  if (queue.isProcessing) {
    logHotPathDebug(
      `[LOG] คิวกำลังประมวลผลอยู่ จะรอให้คำตอบก่อนหน้าส่งเสร็จก่อน (queueKey: ${queueKey})`,
    );
    return;
  }

  scheduleQueueFlush(queueKey, queue.flushDelayMs ?? 0);
}

// ฟังก์ชันสำหรับวิเคราะห์ประเภทเนื้อหาในคิว
function analyzeQueueContent(messages) {
  const analysis = {
    textCount: 0,
    imageCount: 0,
    hasRecentText: false,
    hasRecentImage: false,
    shouldProcessSeparately: false,
    processingStrategy: "combined", // 'combined', 'text_only', 'image_focused'
  };

  for (let i = messages.length - 1; i >= 0; i--) {
    const msg = messages[i];
    if (msg.data?.type === "text") {
      analysis.textCount++;
      if (i >= messages.length - 2) analysis.hasRecentText = true;
    } else if (msg.data?.type === "image") {
      analysis.imageCount++;
      if (i >= messages.length - 2) analysis.hasRecentImage = true;
    }
  }

  // กำหนดกลยุทธ์การประมวลผล
  if (analysis.imageCount === 0) {
    analysis.processingStrategy = "text_only";
  } else if (analysis.textCount === 0) {
    analysis.processingStrategy = "image_focused";
  } else if (
    analysis.imageCount > 2 ||
    (analysis.hasRecentText && analysis.hasRecentImage)
  ) {
    analysis.processingStrategy = "combined";
  } else {
    analysis.processingStrategy = "combined";
  }

  console.log(
    `[LOG] Content Analysis: ${analysis.textCount} texts, ${analysis.imageCount} images, strategy: ${analysis.processingStrategy}`,
  );
  return analysis;
}

function sanitizeTextValue(text, options = {}) {
  if (text === null || text === undefined) {
    return null;
  }

  let sanitized = String(text);
  sanitized = sanitized
    .replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g, "")
    .replace(/\r\n/g, "\n")
    .trim();

  if (!sanitized) {
    return null;
  }

  const maxLength =
    typeof options.maxLength === "number" && options.maxLength > 0
      ? Math.floor(options.maxLength)
      : 6000;

  if (sanitized.length > maxLength) {
    if (options.keepTail) {
      sanitized = sanitized.slice(-maxLength);
    } else {
      sanitized = sanitized.slice(0, maxLength);
    }
  }

  return sanitized;
}

function isLikelyValidBase64Image(value) {
  if (typeof value !== "string") {
    return false;
  }

  const trimmed = value.trim();
  if (trimmed.length < 16) {
    return false;
  }

  if (/[^A-Za-z0-9+/=\r\n]/.test(trimmed)) {
    return false;
  }

  return trimmed.length % 4 === 0;
}

function cloneQueueMessage(message) {
  if (!message || typeof message !== "object") {
    return null;
  }

  const cloned = { ...message };
  if (message.data && typeof message.data === "object") {
    cloned.data = { ...message.data };
  }
  return cloned;
}

function filterMessagesForStrategy(messages, strategy = "original") {
  const meta = {
    droppedImages: 0,
    droppedTexts: 0,
    droppedOthers: 0,
    suspectImages: 0,
  };

  if (!Array.isArray(messages) || messages.length === 0) {
    return { messages: [], meta };
  }

  if (strategy === "recent_text_only") {
    for (let i = messages.length - 1; i >= 0; i--) {
      const cloned = cloneQueueMessage(messages[i]);
      if (!cloned) continue;
      const data =
        (cloned.data && typeof cloned.data === "object" && cloned.data) ||
        (typeof cloned === "object" ? cloned : null);
      if (!data || data.type !== "text") {
        meta.droppedOthers++;
        continue;
      }

      const sanitizedText = sanitizeTextValue(
        data.text !== undefined ? data.text : data.content,
      );
      if (!sanitizedText) {
        meta.droppedTexts++;
        continue;
      }

      if (data.text !== undefined) {
        data.text = sanitizedText;
      } else {
        data.content = sanitizedText;
      }
      return { messages: [cloned], meta };
    }
    return { messages: [], meta };
  }

  const result = [];
  for (const original of messages) {
    const cloned = cloneQueueMessage(original);
    if (!cloned) {
      meta.droppedOthers++;
      continue;
    }

    const data =
      (cloned.data && typeof cloned.data === "object" && cloned.data) ||
      (typeof cloned === "object" ? cloned : null);
    if (!data || typeof data !== "object") {
      meta.droppedOthers++;
      continue;
    }

    const type = data.type;

    if (type === "text") {
      const sanitizedText = sanitizeTextValue(
        data.text !== undefined ? data.text : data.content,
      );
      if (!sanitizedText) {
        meta.droppedTexts++;
        continue;
      }

      if (data.text !== undefined) {
        data.text = sanitizedText;
      } else {
        data.content = sanitizedText;
      }
    } else if (type === "image") {
      const base64 =
        typeof data.base64 === "string" ? data.base64 : data.content;
      const hasContent = typeof base64 === "string" && base64.trim().length > 0;
      const validBase64 = hasContent && isLikelyValidBase64Image(base64);

      if (!hasContent) {
        meta.droppedImages++;
        continue;
      }

      if (!validBase64) {
        if (strategy === "drop_invalid_images") {
          meta.droppedImages++;
          continue;
        }
        meta.suspectImages++;
      }
    } else if (typeof type === "string") {
      // ชนิดอื่น ๆ เช่น audio, file
      meta.droppedOthers++;
      continue;
    } else {
      meta.droppedOthers++;
      continue;
    }

    result.push(cloned);
  }

  return { messages: result, meta };
}

function buildContentSequenceFromMessages(messages, enableMessageMerging = true) {
  const contentSequence = [];
  const combinedTextParts = [];

  if (!Array.isArray(messages)) {
    return {
      contentSequence,
      combinedTextParts,
      hasImages: false,
      textSegmentCount: 0,
    };
  }

  for (const message of messages) {
    const data =
      (message.data && typeof message.data === "object" && message.data) ||
      (typeof message === "object" ? message : null);
    if (!data || typeof data !== "object") {
      continue;
    }

    if (data.type === "text") {
      const rawText =
        data.text !== undefined ? data.text : data.content !== undefined
          ? data.content
          : null;
      const sanitizedText = sanitizeTextValue(rawText);
      if (!sanitizedText) {
        continue;
      }

      combinedTextParts.push(sanitizedText);
      contentSequence.push({ type: "text", content: sanitizedText });
    } else if (data.type === "image") {
      const base64 =
        typeof data.base64 === "string" ? data.base64 : data.content;
      if (!base64 || !base64.trim()) {
        continue;
      }

      contentSequence.push({
        type: "image",
        content: base64,
        description:
          data.description || data.text || "ผู้ใช้ส่งรูปภาพมา",
      });
    }
  }

  return {
    contentSequence,
    combinedTextParts,
    hasImages: contentSequence.some((entry) => entry.type === "image"),
    textSegmentCount: combinedTextParts.length,
  };
}

function cloneContentSequenceEntry(entry) {
  if (!entry || typeof entry !== "object") {
    return null;
  }
  const cloned = { ...entry };
  if (entry.payload && typeof entry.payload === "object") {
    cloned.payload = { ...entry.payload };
  }
  return cloned;
}

function filterContentSequenceForStrategy(sequence, strategy = "original") {
  const meta = {
    droppedImages: 0,
    droppedTexts: 0,
    droppedOthers: 0,
    suspectImages: 0,
  };

  if (!Array.isArray(sequence) || sequence.length === 0) {
    return { sequence: [], textParts: [], meta };
  }

  if (strategy === "recent_text_only") {
    for (let i = sequence.length - 1; i >= 0; i--) {
      const cloned = cloneContentSequenceEntry(sequence[i]);
      if (!cloned) {
        meta.droppedOthers++;
        continue;
      }
      if (cloned.type !== "text") {
        meta.droppedOthers++;
        continue;
      }
      const sanitized = sanitizeTextValue(cloned.content);
      if (!sanitized) {
        meta.droppedTexts++;
        continue;
      }
      cloned.content = sanitized;
      return { sequence: [cloned], textParts: [sanitized], meta };
    }
    return { sequence: [], textParts: [], meta };
  }

  const result = [];
  const textParts = [];

  for (const entry of sequence) {
    const cloned = cloneContentSequenceEntry(entry);
    if (!cloned) {
      meta.droppedOthers++;
      continue;
    }

    if (cloned.type === "text") {
      const sanitized = sanitizeTextValue(cloned.content);
      if (!sanitized) {
        meta.droppedTexts++;
        continue;
      }
      cloned.content = sanitized;
      textParts.push(sanitized);
      result.push(cloned);
    } else if (cloned.type === "image") {
      const base64 = typeof cloned.content === "string" ? cloned.content : "";
      const hasContent = base64.trim().length > 0;
      const validBase64 = hasContent && isLikelyValidBase64Image(base64);

      if (!hasContent) {
        meta.droppedImages++;
        continue;
      }

      if (!validBase64) {
        if (strategy === "drop_invalid_images") {
          meta.droppedImages++;
          continue;
        }
        meta.suspectImages++;
      }

      result.push(cloned);
    } else {
      meta.droppedOthers++;
    }
  }

  return { sequence: result, textParts, meta };
}

function buildStarterThreadQuery(userId, platform = "line", botId = null) {
  const conditions = [buildChatHistoryUserMatch(userId), { role: "user" }];

  const normalizedPlatform =
    typeof platform === "string" && platform.trim() ? platform.trim() : "line";
  conditions.push({ platform: normalizedPlatform });

  const normalizedBotId =
    botId === null || typeof botId === "undefined"
      ? null
      : typeof botId === "string"
        ? botId.trim()
        : String(botId);

  if (normalizedBotId) {
    const botCandidates = [normalizedBotId];
    const botObjectId = toObjectId(normalizedBotId);
    if (botObjectId) botCandidates.push(botObjectId);
    conditions.push({ botId: { $in: botCandidates } });
  } else {
    conditions.push({
      $or: [
        { botId: null },
        { botId: "" },
        { botId: { $exists: false } },
      ],
    });
  }

  return { $and: conditions };
}

async function hasStarterUserHistory(userId, platform = "line", botId = null) {
  const client = await connectDB();
  const db = client.db("chatbot");
  const coll = db.collection("chat_history");
  const query = buildStarterThreadQuery(userId, platform, botId);
  const existing = await coll.findOne(query, { projection: { _id: 1 } });
  return !!existing;
}

async function resolveConversationStarterForQueue(queueContext = {}) {
  const rawSelections = Array.isArray(queueContext.selectedInstructions)
    ? queueContext.selectedInstructions
    : [];
  if (!rawSelections.length) return null;

  const normalizedSelections = normalizeLatestOnlyInstructionSelections(
    rawSelections,
  );
  const objectSelections = normalizedSelections.filter(
    isInstructionSelectionObject,
  );
  if (!objectSelections.length) return null;

  const client = await connectDB();
  const db = client.db("chatbot");
  const docs = await resolveInstructionSelectionsV2(objectSelections, db);
  if (!Array.isArray(docs) || docs.length === 0) return null;

  const byInstructionId = new Map();
  docs.forEach((doc) => {
    if (!doc || !doc.instructionId) return;
    byInstructionId.set(doc.instructionId, doc);
  });

  for (const selection of objectSelections) {
    const doc = byInstructionId.get(selection.instructionId);
    if (!doc) continue;
    const starter = normalizeConversationStarterConfig(doc.conversationStarter);
    if (starter.enabled && Array.isArray(starter.messages) && starter.messages.length > 0) {
      return {
        instructionId: doc.instructionId,
        instructionObjectId:
          doc._id && typeof doc._id.toString === "function"
            ? doc._id.toString()
            : doc._id || null,
        starter,
      };
    }
  }

  return null;
}

function buildConversationStarterHistory(messages = []) {
  const parts = [];
  for (const message of messages) {
    if (!message || typeof message !== "object") continue;
    if (message.type === "text") {
      const content =
        typeof message.content === "string"
          ? message.content.trim()
          : typeof message.text === "string"
            ? message.text.trim()
            : "";
      if (!content) continue;
      parts.push({ type: "text", text: content });
      continue;
    }
    if (message.type === "image") {
      const url =
        typeof message.url === "string" ? message.url.trim() : "";
      if (!url) continue;
      const previewUrl =
        typeof message.previewUrl === "string" && message.previewUrl.trim()
          ? message.previewUrl.trim()
          : url;
      parts.push({
        type: "image",
        url,
        previewUrl,
        alt: typeof message.alt === "string" ? message.alt.trim() : "",
        caption: typeof message.alt === "string" ? message.alt.trim() : "",
      });
      continue;
    }
    if (message.type === "video") {
      const url =
        typeof message.url === "string" ? message.url.trim() : "";
      if (!url) continue;
      const previewUrl =
        typeof message.previewUrl === "string" && message.previewUrl.trim()
          ? message.previewUrl.trim()
          : "";
      parts.push({
        type: "video",
        url,
        previewUrl,
        alt: typeof message.alt === "string" ? message.alt.trim() : "",
        caption: typeof message.alt === "string" ? message.alt.trim() : "",
      });
    }
  }

  if (parts.length === 0) return "";
  if (parts.length === 1 && parts[0].type === "text") {
    return parts[0].text;
  }
  return JSON.stringify(parts);
}

async function sendLineConversationStarterSequence(
  userId,
  messages = [],
  queueContext = {},
) {
  const payloads = [];
  const normalizedMessages = normalizeConversationStarterConfig({
    enabled: true,
    messages,
  }).messages;

  for (const message of normalizedMessages) {
    if (message.type === "text") {
      const text = normalizeOutgoingText(message.content || "");
      if (!text) continue;
      payloads.push({
        type: "text",
        text: text.slice(0, 4000),
      });
      continue;
    }

    if (message.type === "image") {
      if (!message.url) continue;
      payloads.push({
        type: "image",
        originalContentUrl: message.url,
        previewImageUrl: message.previewUrl || message.url,
      });
      continue;
    }

    if (message.type === "video") {
      if (!message.url) continue;
      const previewUrl =
        typeof message.previewUrl === "string" ? message.previewUrl.trim() : "";
      if (!previewUrl) {
        continue;
      }
      payloads.push({
        type: "video",
        originalContentUrl: message.url,
        previewImageUrl: previewUrl,
      });
    }
  }

  if (!payloads.length) return false;

  const botId = queueContext.botId || queueContext.lineBotId || null;
  let client = null;
  try {
    if (queueContext.channelAccessToken && queueContext.channelSecret) {
      client = createLineClient(
        queueContext.channelAccessToken,
        queueContext.channelSecret,
      );
    } else if (queueContext.lineClient) {
      client = queueContext.lineClient;
    } else {
      client = await getLineClientForContext(botId);
    }
  } catch (error) {
    console.error("[Starter] LINE client init failed:", error?.message || error);
    return false;
  }

  if (!client) {
    console.error("[Starter] ไม่พบ LINE client สำหรับส่งข้อความเริ่มต้น");
    return false;
  }

  let sentCount = 0;
  for (const payload of payloads) {
    try {
      await client.pushMessage(userId, payload);
      sentCount += 1;
    } catch (error) {
      console.error(
        "[Starter] ส่งข้อความเริ่มต้น LINE บางรายการไม่สำเร็จ:",
        error?.message || error,
      );
    }
  }
  return sentCount > 0;
}

async function sendFacebookConversationStarterSequence(
  userId,
  messages = [],
  queueContext = {},
) {
  const accessToken =
    queueContext.facebookAccessToken ||
    queueContext.accessToken ||
    queueContext.pageAccessToken ||
    null;
  if (!accessToken) {
    console.error("[Starter] ไม่พบ Facebook access token สำหรับส่งข้อความ");
    return false;
  }

  const normalizedMessages = normalizeConversationStarterConfig({
    enabled: true,
    messages,
  }).messages;
  if (!normalizedMessages.length) return false;

  let sentCount = 0;
  let imageCounter = 0;
  for (const message of normalizedMessages) {
    if (message.type === "text") {
      const text = normalizeOutgoingText(message.content || "");
      if (!text) continue;
      try {
        await sendFacebookMessage(
          userId,
          text,
          accessToken,
          { metadata: "ai_generated", selectedImageCollections: null },
        );
        sentCount += 1;
      } catch (error) {
        console.error(
          "[Starter] ส่งข้อความเริ่มต้น Facebook (text) ไม่สำเร็จ:",
          error?.message || error,
        );
      }
      continue;
    }

    if (message.type === "image" && message.url) {
      imageCounter += 1;
      const label =
        (typeof message.alt === "string" && message.alt.trim()) ||
        (typeof message.fileName === "string" && message.fileName.trim()) ||
        `Starter Image ${imageCounter}`;
      const assetsMap = buildAssetsLookup([
        {
          label,
          url: message.url,
          thumbUrl: message.previewUrl || message.url,
          fileName: message.fileName || "",
          alt: message.alt || "",
        },
      ]);
      try {
        await sendFacebookMessage(
          userId,
          `#[IMAGE:${label}]`,
          accessToken,
          { metadata: "ai_generated", selectedImageCollections: null },
          assetsMap,
        );
        sentCount += 1;
      } catch (error) {
        console.error(
          "[Starter] ส่งข้อความเริ่มต้น Facebook (image) ไม่สำเร็จ:",
          error?.message || error,
        );
      }
      continue;
    }

    if (message.type === "video" && message.url) {
      try {
        await axios.post(
          "https://graph.facebook.com/v18.0/me/messages",
          {
            recipient: { id: userId },
            message: {
              attachment: {
                type: "video",
                payload: {
                  url: message.url,
                  is_reusable: true,
                },
              },
              metadata: "ai_generated",
            },
          },
          {
            params: { access_token: accessToken },
            headers: { "Content-Type": "application/json" },
          },
        );
        sentCount += 1;
      } catch (error) {
        console.error(
          "[Starter] ส่งข้อความเริ่มต้น Facebook (video) ไม่สำเร็จ:",
          error?.message || error,
        );
      }
    }
  }

  return sentCount > 0;
}

