                        quantity: { type: "number", description: "จำนวนหน่วย/ชุด (สินค้าปกติ=จำนวนชิ้น, โปรโมชั่น=จำนวนชุด)" },
                        price: { type: "number", description: "ราคาต่อหน่วย (ใส่ 0 ถ้าเป็นโปรโมชั่นที่ไม่รู้ราคาแยก)" },
