// Short link redirect (used in notifications)
app.get("/s/:code", async (req, res) => {
  try {
    const code = typeof req.params.code === "string" ? req.params.code.trim() : "";
    if (!isValidShortCode(code)) {
      return res.status(404).send("Not Found");
    }
    const client = await connectDB();
    const db = client.db("chatbot");
    const doc = await resolveShortLink(db, code);
    if (!doc?.targetUrl) {
      return res.status(404).send("Not Found");
    }

    db.collection(SHORT_LINK_COLLECTION)
      .updateOne(
        { _id: doc._id },
        { $inc: { hitCount: 1 }, $set: { lastAccessedAt: new Date() } },
      )
      .catch((err) => {
        console.warn("[ShortLink] Update hit count failed:", err?.message || err);
      });

    return res.redirect(doc.targetUrl);
  } catch (err) {
    console.error("[ShortLink] Redirect error:", err?.message || err);
    return res.status(500).send("Error");
  }
});

// ============================ Line Bot Management API ============================

// Dynamic Line Bot webhook handler
app.post("/webhook/line/:botId", async (req, res) => {
  try {
    const { botId } = req.params;
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("line_bots");

    const escapeRegex = (value = "") =>
      value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const escapedBotId = escapeRegex(botId);
    const queryConditions = [
      { webhookUrl: { $regex: `${escapedBotId}$`, $options: "i" } },
    ];

    if (ObjectId.isValid(botId)) {
      queryConditions.push({ _id: new ObjectId(botId) });
    }

    const lineBot = await coll.findOne({ $or: queryConditions });

    if (!lineBot) {
      return res.status(404).json({ error: "Line Bot ไม่พบหรือไม่เปิดใช้งาน" });
    }

    const botIsActive = lineBot.status === "active";
    const pageRuntime = await getAgentRuntimeForPage(
      "line",
      lineBot._id ? lineBot._id.toString() : botId,
    );
    const allowInbound = botIsActive || pageRuntime.managed;

    if (!allowInbound) {
      return res.status(404).json({ error: "Line Bot ไม่พบหรือไม่เปิดใช้งาน" });
    }

    const disableAiReply = pageRuntime.managed
      ? pageRuntime.mode === "human-only"
      : !botIsActive;

    // Create Line client for this bot
    const lineConfig = {
      channelAccessToken: lineBot.channelAccessToken,
      channelSecret: lineBot.channelSecret,
    };
    const lineClient = new line.Client(lineConfig);

    // Handle Line webhook events
    const events = Array.isArray(req.body?.events) ? req.body.events : [];

    if (events.length === 0) {
      console.warn(
        `[Line Bot Webhook] Received request without events for identifier: ${botId}`,
      );
      return res.status(200).json({ status: "NO_EVENTS" });
    }

    const queueOptions = {
      botType: "line",
      platform: "line",
      botId: lineBot._id ? lineBot._id.toString() : null,
      lineBotId: lineBot._id ? lineBot._id.toString() : botId,
      lineClient,
      channelAccessToken: lineBot.channelAccessToken,
      channelSecret: lineBot.channelSecret,
      aiModel:
        pageRuntime.managed && pageRuntime.customerDefaultModel
          ? pageRuntime.customerDefaultModel
          : lineBot.aiModel || null,
      selectedInstructions: lineBot.selectedInstructions || [],
      botName: lineBot.name || null,
      selectedImageCollections: lineBot.selectedImageCollections || null,
      disableAiReply,
      agentManaged: pageRuntime.managed,
      agentId: pageRuntime.agentId || null,
      agentMode: pageRuntime.mode || null,
      botStatus: lineBot.status || null,
      runtimePriority: pageRuntime.managed ? "agent_mode" : "bot_status",
    };

    for (const event of events) {
      try {
        await handleLineEvent(event, queueOptions);
      } catch (eventError) {
        console.error(
          `[Line Bot: ${lineBot.name}] Error handling event:`,
          eventError,
        );
      }
    }

    res.json({ status: "OK" });
  } catch (err) {
    console.error("Error handling Line webhook:", err);
    res.status(500).json({ error: "เกิดข้อผิดพลาดในการประมวลผล webhook" });
  }
});

// ============================ Facebook Bot Webhook Handler ============================

// Facebook Webhook verification (GET) and events (POST)
app.get("/webhook/facebook/:botId", async (req, res) => {
  try {
    const { botId } = req.params;
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("facebook_bots");

    // Find the Facebook Bot by ID
    const facebookBot = ObjectId.isValid(botId)
      ? await coll.findOne({ _id: new ObjectId(botId) })
      : null;

    if (!facebookBot || facebookBot.status !== "active") {
      // สำหรับขั้นตอน verify อนุญาต status อื่น ๆ ได้
      if (!facebookBot) {
        return res.status(404).send("Facebook Bot not found");
      }
    }

    // Handle Facebook webhook verification
    if (req.query["hub.mode"] === "subscribe") {
      if (req.query["hub.verify_token"] === facebookBot.verifyToken) {
        return res.status(200).send(req.query["hub.challenge"]);
      } else {
        console.warn(
          `[Facebook Bot: ${facebookBot.name}] Invalid verify token received: ${req.query["hub.verify_token"]}`,
        );
      }
    }

    return res.status(400).send("Invalid verification request");
  } catch (err) {
    console.error("Error handling Facebook webhook verification:", err);
    res.status(500).send("Server error");
  }
});

// Dynamic Facebook Bot webhook handler (POST events)
app.post("/webhook/facebook/:botId", async (req, res) => {
  try {
    const { botId } = req.params;
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("facebook_bots");

    // Find the Facebook Bot by ID
    const facebookBot = ObjectId.isValid(botId)
      ? await coll.findOne({ _id: new ObjectId(botId) })
      : null;

    if (!facebookBot) {
      return res.status(404).json({ error: "Facebook Bot ไม่พบ" });
    }

    const botIsActive = facebookBot.status === "active";
    const pageRuntime = await getAgentRuntimeForPage(
      "facebook",
      facebookBot._id ? facebookBot._id.toString() : botId,
    );
    const disableAiReply = pageRuntime.managed
      ? pageRuntime.mode === "human-only"
      : !botIsActive;

    const pageId = facebookBot.pageId || facebookBot._id.toString();
    const accessToken = facebookBot.accessToken;

    const queueOptionsBase = {
      botType: "facebook",
      platform: "facebook",
      botId: facebookBot._id ? facebookBot._id.toString() : null,
      facebookAccessToken: facebookBot.accessToken,
      aiModel:
        pageRuntime.managed && pageRuntime.customerDefaultModel
          ? pageRuntime.customerDefaultModel
          : facebookBot.aiModel || null,
      selectedInstructions: facebookBot.selectedInstructions || [],
      botName: facebookBot.name || null,
      selectedImageCollections: facebookBot.selectedImageCollections || null,
      disableAiReply,
      agentManaged: pageRuntime.managed,
      agentId: pageRuntime.agentId || null,
      agentMode: pageRuntime.mode || null,
      botStatus: facebookBot.status || null,
      runtimePriority: pageRuntime.managed ? "agent_mode" : "bot_status",
    };

    // Respond immediately to avoid Facebook retries
    res.status(200).json({ status: "EVENT_RECEIVED" });

    // Process webhook events asynchronously
    if (req.body.object === "page") {
      for (let entry of req.body.entry) {
        // Handle feed/comment events
        if (entry.changes) {
          for (let change of entry.changes) {
            if (change.field !== "feed" || !change.value) continue;
            const value = change.value;
            const postId =
              value.post_id || value.post?.id || value.parent_id || null;

            // Upsert post whenever we see feed change (post/comment/share)
            if (postId) {
              upsertFacebookPost(db, facebookBot, postId, "webhook").catch(
                (err) => {
                  console.error(
                    "[Facebook Webhook] Error upserting post:",
                    err?.message || err,
                  );
                },
              );
            }

            // Handle new comments
            if (value.item === "comment" && value.verb === "add") {
              if (disableAiReply) {
                continue;
              }
              const commentData = {
                id: value.comment_id,
                message: value.message,
                from: value.from,
              };

              handleFacebookComment(
                pageId,
                postId,
                commentData,
                accessToken,
                facebookBot,
              ).catch((err) => {
                console.error("[Facebook Webhook] Error processing comment:", err);
              });
            }
          }
        }

        // Handle messaging events (existing code)
        if (entry.messaging && Array.isArray(entry.messaging)) {
          for (let messagingEvent of entry.messaging) {
            // จัดการข้อความที่ส่งจากเพจเอง (echo) – ถือว่าเป็นข้อความจากแอดมินเพจ
            if (messagingEvent.message?.is_echo) {
              try {
                const senderId = String(messagingEvent.sender?.id || "").trim();
                const recipientId = String(
                  messagingEvent.recipient?.id || "",
                ).trim();
                const pageIdStr = String(pageId || "").trim();
                let targetUserId = "";

                // รองรับ payload ได้ทั้งกรณี sender=page,recipient=user และ sender=user,recipient=page
                if (senderId && recipientId) {
                  if (senderId === pageIdStr && recipientId !== pageIdStr) {
                    targetUserId = recipientId;
                  } else if (
                    recipientId === pageIdStr &&
                    senderId !== pageIdStr
                  ) {
                    targetUserId = senderId;
                  } else {
                    targetUserId = recipientId || senderId;
                  }
                } else {
                  targetUserId = recipientId || senderId;
                }

                // ป้องกันกรณี fallback แล้วได้ pageId แทน userId
                if (targetUserId === pageIdStr) {
                  if (senderId && senderId !== pageIdStr) {
                    targetUserId = senderId;
                  } else if (recipientId && recipientId !== pageIdStr) {
                    targetUserId = recipientId;
                  }
                }
                const text = messagingEvent.message?.text?.trim();
                const metadata =
                  typeof messagingEvent.message?.metadata === "string"
                    ? messagingEvent.message.metadata.trim()
                    : "";
                const isBroadcastMessage = metadata === "broadcast_auto";

                // ข้ามข้อความที่ระบบส่งอัตโนมัติ (เช่น AI / follow-up) เพื่อหลีกเลี่ยงการบันทึกซ้ำ
                const automatedMetadata = [
                  "ai_generated",
                  "follow_up_auto",
                  "keyword_control_auto",
                ];
                if (metadata && automatedMetadata.includes(metadata)) {
                  console.log(
                    `[Facebook Bot: ${facebookBot.name}] Skip echo for automated message (${metadata}) to ${targetUserId}`,
                  );
                  continue;
                }

                if (!targetUserId) {
                  continue;
                }

                const client = await connectDB();
                const db = client.db("chatbot");
                const coll = db.collection("chat_history");

                // ตรวจสอบ keyword actions ก่อน (เช่น เปิด/ปิด AI, ปิดระบบติดตาม)
                const keywordResult = await detectKeywordAction(
                  text,
                  facebookBot.keywordSettings || {},
                  targetUserId,
                  "facebook",
                  facebookBot._id?.toString?.() || null,
                  true, // isFromAdmin = true
                );

                if (keywordResult.action) {
                  // ถ้ามี keyword action และต้องการส่งข้อความตอบกลับ
                  if (keywordResult.sendResponse && keywordResult.message) {
                    try {
                      await sendFacebookMessage(
                        targetUserId,
                        keywordResult.message,
                        facebookBot.accessToken,
                        { metadata: "keyword_control_auto" },
                      );
                    } catch (controlReplyError) {
                      console.error(
                        `[Facebook Bot: ${facebookBot.name}] Error sending keyword control response:`,
                        controlReplyError?.message || controlReplyError,
                      );
                    }

                    const controlDoc = {
                      senderId: targetUserId,
                      role: "assistant",
                      content: `[ระบบ] ${keywordResult.message}`,
                      timestamp: new Date(),
                      source: "admin_chat",
                      platform: "facebook",
                      botId: facebookBot?._id?.toString?.() || null,
                    };
                    const controlInsertResult = await coll.insertOne(controlDoc);
                    if (controlInsertResult?.insertedId) {
                      controlDoc._id = controlInsertResult.insertedId;
                    }

                    try {
                      await resetUserUnreadCount(targetUserId);
                    } catch (_) { }

                    // แจ้ง UI แอดมินแบบเรียลไทม์
                    try {
                      io.to("admin").emit("newMessage", {
                        userId: targetUserId,
                        message: controlDoc,
                        sender: "assistant",
                        timestamp: controlDoc.timestamp,
                      });
                    } catch (_) { }
                  }
                  continue;
                }

                // คำสั่งควบคุม [ปิด]/[เปิด] (legacy)
                if (text === "[ปิด]" || text === "[เปิด]") {
                  const enable = text === "[เปิด]";
                  await setUserStatus(targetUserId, enable);

                  const controlText = enable
                    ? "เปิด AI สำหรับผู้ใช้นี้แล้ว"
                    : "ปิด AI สำหรับผู้ใช้นี้ชั่วคราวแล้ว";
                  const controlDoc = {
                    senderId: targetUserId,
                    role: "assistant",
                    content: `[ระบบ] ${controlText}`,
                    timestamp: new Date(),
                    source: "admin_chat",
                    platform: "facebook",
                    botId: facebookBot?._id?.toString?.() || null,
                  };
                  const controlInsertResult = await coll.insertOne(controlDoc);
                  if (controlInsertResult?.insertedId) {
                    controlDoc._id = controlInsertResult.insertedId;
                  }

                  try {
                    await resetUserUnreadCount(targetUserId);
                  } catch (_) { }

                  // แจ้ง UI แอดมินแบบเรียลไทม์
                  try {
                    io.to("admin").emit("newMessage", {
                      userId: targetUserId,
                      message: controlDoc,
                      sender: "assistant",
                      timestamp: controlDoc.timestamp,
                    });
                  } catch (_) { }
                } else {
                  // บันทึกข้อความจากแอดมินเพจเป็น assistant (เฉพาะกรณีไม่ใช่คำสั่ง)
                  const baseDoc = {
                    senderId: targetUserId,
                    role: "assistant",
                    content: text || "ไฟล์แนบ",
                    timestamp: new Date(),
                    source:
                      metadata === "admin_manual" || isBroadcastMessage
                        ? "admin_chat" // มาจากแอดมินหน้าเว็บ (ส่งผ่านระบบ)
                        : "admin_page", // มาจากแอดมินตอบในเพจโดยตรง (Facebook inbox)
                    metadata: metadata || null,
                    platform: "facebook",
                    botId: facebookBot?._id?.toString?.() || null,
                  };
                  const baseInsertResult = await coll.insertOne(baseDoc);
                  if (baseInsertResult?.insertedId) {
                    baseDoc._id = baseInsertResult.insertedId;
                  }
                  // ข้อความทั่วไปจากแอดมินเพจ – อัปเดต UI และ unread count
                  try {
                    await resetUserUnreadCount(targetUserId);
                  } catch (_) { }
                  try {
                    io.to("admin").emit("newMessage", {
                      userId: targetUserId,
                      message: baseDoc,
                      sender: "assistant",
                      timestamp: baseDoc.timestamp,
                    });
                  } catch (_) { }
                }
              } catch (echoErr) {
                console.error(
                  `[Facebook Bot: ${facebookBot.name}] Error handling admin echo:`,
                  echoErr.message,
                );
              }
              continue;
            }

            if (messagingEvent.message) {
              const senderId = messagingEvent.sender.id;
              try {
                await ensureFacebookProfileDisplayName(
                  senderId,
                  facebookBot.accessToken,
                );
              } catch (profileErr) {
                console.warn(
                  `[Facebook Bot: ${facebookBot.name}] อัปเดตโปรไฟล์ ${senderId} ไม่สำเร็จ:`,
                  profileErr?.message || profileErr,
                );
              }
              const queueOptions = { ...queueOptionsBase };
              const facebookRuntimeInstructionContext =
                await resolveInstructionMetaForRuntime(
                  queueOptions.selectedInstructions,
                  null,
                  { policy: "latest_only" },
                );
              const facebookRuntimeInstructionRefs =
                facebookRuntimeInstructionContext.instructionRefs;
              const facebookRuntimeInstructionMeta =
                facebookRuntimeInstructionContext.instructionMeta;
              const itemsToQueue = [];
              const audioAttachments = [];
              const messageText = messagingEvent.message.text;

              if (messageText) {
                itemsToQueue.push({
                  data: { type: "text", text: messageText },
                });
              }

              if (messagingEvent.message.attachments) {
                for (const attachment of messagingEvent.message.attachments) {
                  if (attachment.type === "image" && attachment.payload?.url) {
                    try {
                      const base64 = await fetchFacebookImageAsBase64(
                        attachment.payload.url,
                      );
                      itemsToQueue.push({
                        data: {
                          type: "image",
                          base64,
                          text: "ผู้ใช้ส่งรูปภาพมา",
                        },
                      });
                    } catch (imgErr) {
                      console.error(
                        `[Facebook Bot: ${facebookBot.name}] Error fetching image:`,
                        imgErr.message,
                      );
                    }
                  } else if (attachment.type === "audio") {
                    audioAttachments.push({
                      type: "audio",
                      payload: {
                        url: attachment.payload?.url || null,
                        id: attachment.payload?.id || null,
                        duration: attachment.payload?.duration || null,
                      },
                    });
                  }
                }
              }

              if (audioAttachments.length > 0) {
                try {
                  console.log(
                    `[Facebook Bot: ${facebookBot.name}] ได้รับไฟล์เสียงจาก ${senderId} (ยังไม่รองรับ, ไม่ตอบกลับอัตโนมัติ)`,
                  );
                  try {
                    await saveChatHistory(
                      senderId,
                      { type: "audio", attachments: audioAttachments },
                      "",
                      "facebook",
                      facebookBot._id ? facebookBot._id.toString() : null,
                      facebookRuntimeInstructionRefs,
                      queueOptions.botName || null,
                      { instructionMeta: facebookRuntimeInstructionMeta },
                    );
                  } catch (historyErr) {
                    console.error(
                      `[Facebook Bot: ${facebookBot.name}] ไม่สามารถบันทึกประวัติไฟล์เสียงได้:`,
                      historyErr.message || historyErr,
                    );
                  }
                } catch (audioErr) {
                  console.error(
                    `[Facebook Bot: ${facebookBot.name}] Error handling audio attachment:`,
                    audioErr.message || audioErr,
                  );
                }
              }

              if (itemsToQueue.length === 0) {
                if (audioAttachments.length === 0) {
                  console.log(
                    `[Facebook Bot: ${facebookBot.name}] ได้รับไฟล์แนบที่ไม่รองรับจาก ${senderId} (ไม่ตอบกลับอัตโนมัติ)`,
                  );
                  try {
                    await saveChatHistory(
                      senderId,
                      {
                        type: "unsupported",
                        attachments: messagingEvent.message.attachments || [],
                      },
                      "",
                      "facebook",
                      facebookBot._id ? facebookBot._id.toString() : null,
                      facebookRuntimeInstructionRefs,
                      queueOptions.botName || null,
                      { instructionMeta: facebookRuntimeInstructionMeta },
                    );
                  } catch (historyErr) {
                    console.error(
                      `[Facebook Bot: ${facebookBot.name}] ไม่สามารถบันทึกประวัติไฟล์แนบที่ไม่รองรับได้:`,
                      historyErr.message || historyErr,
                    );
                  }
                }
                continue;
              }

              console.log(
                `[Facebook Bot: ${facebookBot.name}] รับข้อความเข้าคิวจาก ${senderId}: ${messageText || "[มีรูปภาพ]"}`,
              );

              for (const item of itemsToQueue) {
                try {
                  await addToQueue(senderId, { ...item }, queueOptions);
                } catch (queueErr) {
                  console.error(
                    `[Facebook Bot: ${facebookBot.name}] Error queuing message:`,
                    queueErr,
                  );
                }
              }
            }
          }
        }
      }
    }
  } catch (err) {
    console.error("Error handling Facebook webhook:", err);
    if (!res.headersSent) {
      res.status(500).json({ error: "เกิดข้อผิดพลาดในการประมวลผล webhook" });
    }
  }
});

// ============================ Instagram Bot Webhook Handler ============================

app.get("/webhook/instagram/:botId", async (req, res) => {
  try {
    const { botId } = req.params;

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instagram_bots");
    const escapeRegex = (value = "") =>
      value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const escapedBotId = escapeRegex(botId);
    const queryConditions = [
      { webhookUrl: { $regex: `${escapedBotId}$`, $options: "i" } },
    ];
    if (ObjectId.isValid(botId)) {
      queryConditions.push({ _id: new ObjectId(botId) });
    }
    const instagramBot = await coll.findOne({ $or: queryConditions });

    if (!instagramBot) {
      return res.status(404).send("Instagram Bot not found");
    }

    if (req.query["hub.mode"] === "subscribe") {
      if (req.query["hub.verify_token"] === instagramBot.verifyToken) {
        return res.status(200).send(req.query["hub.challenge"]);
      }
      return res.status(403).send("Invalid verify token");
    }

    return res.status(400).send("Invalid verification request");
  } catch (err) {
    console.error("Error handling Instagram webhook verification:", err);
    res.status(500).send("Server error");
  }
});

app.post("/webhook/instagram/:botId", async (req, res) => {
  try {
    const { botId } = req.params;

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instagram_bots");
    const escapeRegex = (value = "") =>
      value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const escapedBotId = escapeRegex(botId);
    const queryConditions = [
      { webhookUrl: { $regex: `${escapedBotId}$`, $options: "i" } },
    ];
    if (ObjectId.isValid(botId)) {
      queryConditions.push({ _id: new ObjectId(botId) });
    }
    const instagramBot = await coll.findOne({ $or: queryConditions });

    if (!instagramBot) {
      return res.status(404).json({ error: "Instagram Bot ไม่พบ" });
    }

    const botIsActive = instagramBot.status === "active";
    const pageRuntime = await getAgentRuntimeForPage(
      "instagram",
      instagramBot._id.toString(),
    );
    const disableAiReply = pageRuntime.managed
      ? pageRuntime.mode === "human-only"
      : !botIsActive;

    const queueOptionsBase = {
      botType: "instagram",
      platform: "instagram",
      botId: instagramBot._id.toString(),
      instagramAccessToken: resolveMetaAccessToken(instagramBot),
      instagramBusinessAccountId: resolveInstagramSenderId(instagramBot),
      aiModel:
        pageRuntime.managed && pageRuntime.customerDefaultModel
          ? pageRuntime.customerDefaultModel
          : instagramBot.aiModel || null,
      selectedInstructions: instagramBot.selectedInstructions || [],
      botName: getBotDisplayName("instagram", instagramBot),
      selectedImageCollections: instagramBot.selectedImageCollections || null,
      disableAiReply,
      agentManaged: pageRuntime.managed,
      agentId: pageRuntime.agentId || null,
      agentMode: pageRuntime.mode || null,
      botStatus: instagramBot.status || null,
      runtimePriority: pageRuntime.managed ? "agent_mode" : "bot_status",
    };

    res.status(200).json({ status: "EVENT_RECEIVED" });

    const entries = Array.isArray(req.body?.entry) ? req.body.entry : [];
    for (const entry of entries) {
      if (!Array.isArray(entry?.messaging)) continue;
      for (const messagingEvent of entry.messaging) {
        if (messagingEvent?.message?.is_echo) {
          continue;
        }
        if (!messagingEvent?.message) {
          continue;
        }

        const senderId = messagingEvent?.sender?.id;
        if (!senderId) continue;

        const queueOptions = { ...queueOptionsBase };
        const runtimeInstructionContext = await resolveInstructionMetaForRuntime(
          queueOptions.selectedInstructions,
          null,
          { policy: "latest_only" },
        );
        const runtimeInstructionRefs = runtimeInstructionContext.instructionRefs;
        const runtimeInstructionMeta = runtimeInstructionContext.instructionMeta;

        const itemsToQueue = [];
        const audioAttachments = [];
        const messageText = messagingEvent?.message?.text;

        if (messageText) {
          itemsToQueue.push({
            data: { type: "text", text: messageText },
          });
        }

        const attachments = Array.isArray(messagingEvent?.message?.attachments)
          ? messagingEvent.message.attachments
          : [];

        for (const attachment of attachments) {
          if (attachment?.type === "image" && attachment?.payload?.url) {
            try {
              const base64 = await fetchFacebookImageAsBase64(
                attachment.payload.url,
              );
              itemsToQueue.push({
                data: {
                  type: "image",
                  base64,
                  text: "ผู้ใช้ส่งรูปภาพมา",
                },
              });
            } catch (imgErr) {
              console.error(
                `[Instagram Bot: ${instagramBot.name || instagramBot._id}] Error fetching image:`,
                imgErr?.message || imgErr,
              );
            }
          } else if (attachment?.type === "audio") {
            audioAttachments.push({
              type: "audio",
              payload: {
                url: attachment?.payload?.url || null,
                id: attachment?.payload?.id || null,
              },
            });
          }
        }

        if (audioAttachments.length > 0) {
          try {
            console.log(
              `[Instagram Bot: ${instagramBot.name || instagramBot._id}] ได้รับไฟล์เสียงจาก ${senderId} (ยังไม่รองรับ, ไม่ตอบกลับอัตโนมัติ)`,
            );

            await saveChatHistory(
              senderId,
              { type: "audio", attachments: audioAttachments },
              "",
              "instagram",
              queueOptions.botId || null,
              runtimeInstructionRefs,
              queueOptions.botName || null,
              { instructionMeta: runtimeInstructionMeta },
            );
          } catch (audioErr) {
            console.error(
              `[Instagram Bot: ${instagramBot.name || instagramBot._id}] Error handling audio attachment:`,
              audioErr?.message || audioErr,
            );
          }
        }

        if (itemsToQueue.length === 0) {
          if (audioAttachments.length === 0) {
            console.log(
              `[Instagram Bot: ${instagramBot.name || instagramBot._id}] ได้รับไฟล์แนบที่ไม่รองรับจาก ${senderId} (ไม่ตอบกลับอัตโนมัติ)`,
            );
            try {
              await saveChatHistory(
                senderId,
                {
                  type: "unsupported",
                  attachments,
                },
                "",
                "instagram",
                queueOptions.botId || null,
                runtimeInstructionRefs,
                queueOptions.botName || null,
                { instructionMeta: runtimeInstructionMeta },
              );
            } catch (historyErr) {
              console.error(
                "[Instagram] ไม่สามารถบันทึกประวัติไฟล์แนบที่ไม่รองรับได้:",
                historyErr?.message || historyErr,
              );
            }
          }
          continue;
        }

        for (const item of itemsToQueue) {
          try {
            await addToQueue(senderId, { ...item }, queueOptions);
          } catch (queueErr) {
            console.error(
              `[Instagram Bot: ${instagramBot.name || instagramBot._id}] Error queuing message:`,
              queueErr?.message || queueErr,
            );
          }
        }
      }
    }
  } catch (err) {
    console.error("Error handling Instagram webhook:", err);
    if (!res.headersSent) {
      res.status(500).json({ error: "เกิดข้อผิดพลาดในการประมวลผล webhook" });
    }
  }
});

