app.post("/webhook/whatsapp/:botId", async (req, res) => {
  try {
    const { botId } = req.params;

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("whatsapp_bots");
    const escapeRegex = (value = "") =>
      value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const escapedBotId = escapeRegex(botId);
    const queryConditions = [
      { webhookUrl: { $regex: `${escapedBotId}$`, $options: "i" } },
    ];
    if (ObjectId.isValid(botId)) {
      queryConditions.push({ _id: new ObjectId(botId) });
    }
    const whatsappBot = await coll.findOne({ $or: queryConditions });
    if (!whatsappBot) {
      return res.status(404).json({ error: "WhatsApp Bot ไม่พบ" });
    }

    const botIsActive = whatsappBot.status === "active";
    const pageRuntime = await getAgentRuntimeForPage(
      "whatsapp",
      whatsappBot._id.toString(),
    );
    const disableAiReply = pageRuntime.managed
      ? pageRuntime.mode === "human-only"
      : !botIsActive;

    const queueOptionsBase = {
      botType: "whatsapp",
      platform: "whatsapp",
      botId: whatsappBot._id.toString(),
      whatsappAccessToken: resolveMetaAccessToken(whatsappBot),
      whatsappPhoneNumberId: resolveWhatsAppPhoneNumberId(whatsappBot),
      aiModel:
        pageRuntime.managed && pageRuntime.customerDefaultModel
          ? pageRuntime.customerDefaultModel
          : whatsappBot.aiModel || null,
      selectedInstructions: whatsappBot.selectedInstructions || [],
      botName: getBotDisplayName("whatsapp", whatsappBot),
      selectedImageCollections: whatsappBot.selectedImageCollections || null,
      disableAiReply,
      agentManaged: pageRuntime.managed,
      agentId: pageRuntime.agentId || null,
      agentMode: pageRuntime.mode || null,
      botStatus: whatsappBot.status || null,
      runtimePriority: pageRuntime.managed ? "agent_mode" : "bot_status",
    };

    res.status(200).json({ status: "EVENT_RECEIVED" });

    const entries = Array.isArray(req.body?.entry) ? req.body.entry : [];
    for (const entry of entries) {
      const changes = Array.isArray(entry?.changes) ? entry.changes : [];
      for (const change of changes) {
        const value = change?.value || {};
        const messages = Array.isArray(value?.messages) ? value.messages : [];
        for (const incomingMessage of messages) {
          const messageId =
            typeof incomingMessage?.id === "string"
              ? incomingMessage.id.trim()
              : "";
          if (messageId) {
            const dedupeKey = `wa:${messageId}`;
            if (processedIds.has(dedupeKey)) {
              continue;
            }
            processedIds.add(dedupeKey);
          }

          const senderId = incomingMessage?.from;
          if (!senderId) continue;

          const queueOptions = { ...queueOptionsBase };
          const runtimeInstructionContext =
            await resolveInstructionMetaForRuntime(
              queueOptions.selectedInstructions,
              null,
              { policy: "latest_only" },
            );
          const runtimeInstructionRefs =
            runtimeInstructionContext.instructionRefs;
          const runtimeInstructionMeta =
            runtimeInstructionContext.instructionMeta;

          const itemsToQueue = [];
          const audioAttachments = [];
          const incomingType =
            typeof incomingMessage?.type === "string"
              ? incomingMessage.type
              : "";

          if (
            incomingType === "text" &&
            typeof incomingMessage?.text?.body === "string"
          ) {
            const textBody = incomingMessage.text.body.trim();
            if (textBody) {
              itemsToQueue.push({
                data: { type: "text", text: textBody },
              });
            }
          } else if (incomingType === "button") {
            const buttonText =
              typeof incomingMessage?.button?.text === "string"
                ? incomingMessage.button.text.trim()
                : "";
            if (buttonText) {
              itemsToQueue.push({
                data: { type: "text", text: buttonText },
              });
            }
          } else if (incomingType === "interactive") {
            const interactive = incomingMessage?.interactive || {};
            const listTitle =
              typeof interactive?.list_reply?.title === "string"
                ? interactive.list_reply.title.trim()
                : "";
            const buttonTitle =
              typeof interactive?.button_reply?.title === "string"
                ? interactive.button_reply.title.trim()
                : "";
            const interactiveText = listTitle || buttonTitle;
            if (interactiveText) {
              itemsToQueue.push({
                data: { type: "text", text: interactiveText },
              });
            }
          } else if (incomingType === "image") {
            const mediaId = incomingMessage?.image?.id || null;
            if (mediaId && queueOptions.whatsappAccessToken) {
              try {
                const media = await fetchWhatsAppMediaAsBase64(
                  mediaId,
                  queueOptions.whatsappAccessToken,
                );
                itemsToQueue.push({
                  data: {
                    type: "image",
                    base64: media.base64,
                    text:
                      incomingMessage?.image?.caption ||
                      "ผู้ใช้ส่งรูปภาพมา",
                    mime: media.mimeType || null,
                  },
                });
              } catch (imgErr) {
                console.error(
                  `[WhatsApp Bot: ${whatsappBot.name || whatsappBot._id}] Error fetching image media:`,
                  imgErr?.message || imgErr,
                );
              }
            }
          } else if (incomingType === "audio") {
            audioAttachments.push({
              type: "audio",
              payload: {
                id: incomingMessage?.audio?.id || null,
                mimeType: incomingMessage?.audio?.mime_type || null,
              },
            });
          }

          if (audioAttachments.length > 0) {
            try {
              console.log(
                `[WhatsApp Bot: ${whatsappBot.name || whatsappBot._id}] ได้รับไฟล์เสียงจาก ${senderId} (ยังไม่รองรับ, ไม่ตอบกลับอัตโนมัติ)`,
              );

              await saveChatHistory(
                senderId,
                { type: "audio", attachments: audioAttachments },
                "",
                "whatsapp",
                queueOptions.botId || null,
                runtimeInstructionRefs,
                queueOptions.botName || null,
                { instructionMeta: runtimeInstructionMeta },
              );
            } catch (audioErr) {
              console.error(
                `[WhatsApp Bot: ${whatsappBot.name || whatsappBot._id}] Error handling audio attachment:`,
                audioErr?.message || audioErr,
              );
            }
          }

          if (itemsToQueue.length === 0) {
            if (audioAttachments.length === 0) {
              console.log(
                `[WhatsApp Bot: ${whatsappBot.name || whatsappBot._id}] ได้รับไฟล์แนบที่ไม่รองรับจาก ${senderId} (ไม่ตอบกลับอัตโนมัติ)`,
              );
              try {
                await saveChatHistory(
                  senderId,
                  {
                    type: "unsupported",
                    attachments: [incomingMessage],
                  },
                  "",
                  "whatsapp",
                  queueOptions.botId || null,
                  runtimeInstructionRefs,
                  queueOptions.botName || null,
                  { instructionMeta: runtimeInstructionMeta },
                );
              } catch (historyErr) {
                console.error(
                  "[WhatsApp] ไม่สามารถบันทึกประวัติไฟล์แนบที่ไม่รองรับได้:",
                  historyErr?.message || historyErr,
                );
              }
            }
            continue;
          }

          for (const item of itemsToQueue) {
            try {
              await addToQueue(senderId, { ...item }, queueOptions);
            } catch (queueErr) {
              console.error(
                `[WhatsApp Bot: ${whatsappBot.name || whatsappBot._id}] Error queuing message:`,
                queueErr?.message || queueErr,
              );
            }
          }
        }
      }
    }
  } catch (err) {
    console.error("Error handling WhatsApp webhook:", err);
    if (!res.headersSent) {
      res.status(500).json({ error: "เกิดข้อผิดพลาดในการประมวลผล webhook" });
    }
  }
});

function isHttpOrHttpsUrl(value) {
  if (typeof value !== "string") return false;
  return /^https?:\/\//i.test(value.trim());
}

async function buildLineMessagesFromTemplate(
  message,
  selectedImageCollections = null,
  customAssetsMap = null,
) {
  const normalizedMessage = normalizeOutgoingText(message);
  if (!normalizedMessage) return [];

  const parts = String(normalizedMessage || "")
    .split("[cut]")
    .map((p) => p.trim())
    .filter((p) => p.length > 0);
  if (!parts.length) return [];

  const hasImageToken = /#\[\s*IMAGE\s*:/i.test(normalizedMessage);
  const assetsMap = hasImageToken
    ? customAssetsMap || (await getAssetsMapForBot(selectedImageCollections))
    : null;
  const payloads = [];
  const maxTextLength = 4000;

  for (const part of parts) {
    const segments = hasImageToken
      ? parseMessageSegmentsByImageTokens(part, assetsMap)
      : [{ type: "text", text: part }];
    for (const seg of segments) {
      if (seg.type === "text") {
        const textChunks = chunkTextByLength(seg.text || "", maxTextLength);
        textChunks.forEach((chunk) => {
          payloads.push({ type: "text", text: chunk });
        });
        continue;
      }

      if (seg.type === "image" && seg.url) {
        const originalContentUrl =
          typeof seg.url === "string" ? seg.url.trim() : "";
        if (!isHttpOrHttpsUrl(originalContentUrl)) {
          const fallbackText = `[ไม่สามารถส่งรูป ${seg.label || "image"} ได้]`;
          payloads.push({ type: "text", text: fallbackText });
          continue;
        }

        const previewCandidate =
          typeof seg.thumbUrl === "string" ? seg.thumbUrl.trim() : "";
        const previewImageUrl = isHttpOrHttpsUrl(previewCandidate)
          ? previewCandidate
          : originalContentUrl;

        payloads.push({
          type: "image",
          originalContentUrl,
          previewImageUrl,
        });
      }
    }
  }

  return payloads;
}

async function sendLineMessagesByChunks(
  client,
  recipientId,
  payloads,
  replyToken = null,
) {
  if (!client || !recipientId || !Array.isArray(payloads) || !payloads.length) {
    return false;
  }

  const chunks = [];
  for (let i = 0; i < payloads.length; i += 5) {
    chunks.push(payloads.slice(i, i + 5));
  }
  if (!chunks.length) return false;

  let startChunkIndex = 0;
  if (replyToken) {
    const firstChunk = chunks[0];
    await client.replyMessage(
      replyToken,
      firstChunk.length === 1 ? firstChunk[0] : firstChunk,
    );
    startChunkIndex = 1;
  }

  for (let i = startChunkIndex; i < chunks.length; i++) {
    const chunk = chunks[i];
    await client.pushMessage(
      recipientId,
      chunk.length === 1 ? chunk[0] : chunk,
    );
  }

  return true;
}

// Helper function to send Facebook message
async function sendFacebookMessage(
  recipientId,
  message,
  accessToken,
  options = {},
  customAssetsMap = null,
) {
  const {
    metadata = null,
    messagingType = null,
    tag = null,
    selectedImageCollections = null,
  } = options || {};
  const normalizedMessage = normalizeOutgoingText(message);
  // แยกข้อความตามตัวแบ่ง [cut] → จากนั้น parse #[IMAGE:<label>] เป็น segments
  const parts = String(normalizedMessage || "")
    .split("[cut]")
    .map((p) => p.trim())
    .filter((p) => p.length > 0);

  // ใช้ customAssetsMap ถ้ามี ไม่เช่นนั้นดึงจาก database
  const assetsMap =
    customAssetsMap || (await getAssetsMapForBot(selectedImageCollections));
  const maxLength = 2000;

  for (const part of parts) {
    const segments = parseMessageSegmentsByImageTokens(part, assetsMap);
    for (const seg of segments) {
      if (seg.type === "text") {
        const text = seg.text || "";
        // chunk text to maxLength
        for (let i = 0; i < text.length; i += maxLength) {
          const chunk = text.slice(i, i + maxLength);
          if (!chunk.trim()) continue;
          try {
            const payload = { text: chunk };
            if (metadata) {
              payload.metadata = metadata;
            }
            const body = {
              recipient: { id: recipientId },
              message: payload,
            };
            if (messagingType) {
              body.messaging_type = messagingType;
            }
            if (tag) {
              body.tag = tag;
            }
            const response = await axios.post(
              `https://graph.facebook.com/v18.0/me/messages`,
              body,
              {
                params: { access_token: accessToken },
                headers: { "Content-Type": "application/json" },
              },
            );
            logHotPathDebug(
              "Facebook text sent:",
              response.data?.message_id || "ok",
            );
          } catch (error) {
            const status = error.response?.status;
            const fbMessage =
              error.response?.data?.error?.message || error.message;
            const conciseError = status
              ? `Facebook API ${status}: ${fbMessage}`
              : fbMessage;
            console.error("Error sending Facebook text:", conciseError);
            throw new Error(conciseError);
          }
        }
      } else if (seg.type === "image") {
        const mode = await getSettingValue("facebookImageSendMode", "upload");
        const tryUploadFirst = mode === "upload";
        let sent = false;
        const sendByUrl = async () => {
          const messagePayload = {
            attachment: {
              type: "image",
              payload: { url: seg.url, is_reusable: true },
            },
          };
          if (metadata) {
            messagePayload.metadata = metadata;
          }
          const body = {
            recipient: { id: recipientId },
            message: messagePayload,
          };
          if (messagingType) {
            body.messaging_type = messagingType;
          }
          if (tag) {
            body.tag = tag;
          }
          const response = await axios.post(
            `https://graph.facebook.com/v18.0/me/messages`,
            body,
            {
              params: { access_token: accessToken },
              headers: { "Content-Type": "application/json" },
            },
          );
          logHotPathDebug(
            "Facebook image sent (url):",
            response.data?.message_id || "ok",
            seg.label,
          );
        };
        const sendByUpload = async () => {
          await sendFacebookImageByUpload(recipientId, seg, accessToken, {
            metadata,
            messagingType,
            tag,
          });
          logHotPathDebug("Facebook image sent (upload):", seg.label);
        };
        try {
          if (tryUploadFirst) {
            await sendByUpload();
          } else {
            await sendByUrl();
          }
          sent = true;
        } catch (firstErr) {
          console.error(
            `Facebook image ${tryUploadFirst ? "upload" : "url"} mode failed:`,
            firstErr?.message || firstErr,
          );
          try {
            if (tryUploadFirst) {
              await sendByUrl();
            } else {
              await sendByUpload();
            }
            sent = true;
          } catch (secondErr) {
            console.error(
              "Facebook image both modes failed:",
              secondErr?.message || secondErr,
            );
            const alt = seg.alt ? `\n(รูป: ${seg.alt})` : "";
            try {
              const fallbackPayload = {
                text: `[ไม่สามารถส่งรูป ${seg.label}]${alt}`,
              };
              if (metadata) {
                fallbackPayload.metadata = metadata;
              }
              const body = {
                recipient: { id: recipientId },
                message: fallbackPayload,
              };
              if (messagingType) {
                body.messaging_type = messagingType;
              }
              if (tag) {
                body.tag = tag;
              }
              await axios.post(
                `https://graph.facebook.com/v18.0/me/messages`,
                body,
                {
                  params: { access_token: accessToken },
                  headers: { "Content-Type": "application/json" },
                },
              );
            } catch (_) { }
          }
        }
      }
    }
  }
}

// Upload image to Facebook to obtain attachment_id, then send it
async function sendFacebookImageMessage(
  recipientId,
  image,
  accessToken,
  options = {},
) {
  const { metadata = null, messagingType = null, tag = null } = options || {};
  if (!image || !image.url) {
    throw new Error("ไม่มี URL สำหรับรูปภาพ");
  }


  try {
    const messagePayload = {
      attachment: {
        type: "image",
        payload: {
          url: image.url,
          is_reusable: true,
        },
      },
    };
    if (metadata) {
      messagePayload.metadata = metadata;
    }
    const body = {
      recipient: { id: recipientId },
      message: messagePayload,
    };
    if (messagingType) {
      body.messaging_type = messagingType;
    }
    if (tag) {
      body.tag = tag;
    }
    const response = await axios.post(
      `https://graph.facebook.com/v18.0/me/messages`,
      body,
      {
        params: { access_token: accessToken },
        headers: { "Content-Type": "application/json" },
      },
    );

  } catch (error) {
    const status = error.response?.status;
    const fbMessage = error.response?.data?.error?.message || error.message;
    const fbErrorCode = error.response?.data?.error?.code;
    const conciseError = status
      ? `Facebook API ${status}: ${fbMessage}`
      : fbMessage;
    console.error("[FollowUp Error] Facebook image send failed:", {
      recipientId,
      imageUrl: image.url,
      status,
      errorCode: fbErrorCode,
      message: fbMessage,
    });
    throw new Error(conciseError);
  }
}

async function sendFacebookImageByUpload(
  recipientId,
  seg,
  accessToken,
  options = {},
) {
  const { metadata = null, messagingType = null, tag = null } = options || {};
  const { buffer, filename, contentType } =
    await readInstructionAssetBuffer(seg);

  const form = new FormData();
  form.append(
    "message",
    JSON.stringify({
      attachment: { type: "image", payload: { is_reusable: true } },
    }),
  );
  form.append("filedata", buffer, { filename, contentType });

  // 1) Upload attachment to get attachment_id
  const uploadRes = await axios.post(
    `https://graph.facebook.com/v18.0/me/message_attachments`,
    form,
    {
      params: { access_token: accessToken },
      headers: form.getHeaders(),
    },
  );
  const attachment_id = uploadRes.data?.attachment_id;
  if (!attachment_id) throw new Error("ไม่ได้รับ attachment_id จาก Facebook");

  // 2) Send the message referencing attachment_id
  const messagePayload = {
    attachment: { type: "image", payload: { attachment_id } },
  };
  if (metadata) {
    messagePayload.metadata = metadata;
  }
  const body = {
    recipient: { id: recipientId },
    message: messagePayload,
  };
  if (messagingType) {
    body.messaging_type = messagingType;
  }
  if (tag) {
    body.tag = tag;
  }
  await axios.post(`https://graph.facebook.com/v22.0/me/messages`, body, {
    params: { access_token: accessToken },
    headers: { "Content-Type": "application/json" },
  });
}

async function sendInstagramMessage(
  recipientId,
  message,
  accessToken,
  instagramSenderId,
  options = {},
  customAssetsMap = null,
) {
  const { selectedImageCollections = null } = options || {};
  const normalizedMessage = normalizeOutgoingText(message);
  if (!normalizedMessage || !accessToken || !instagramSenderId || !recipientId) {
    return;
  }

  const parts = String(normalizedMessage || "")
    .split("[cut]")
    .map((p) => p.trim())
    .filter((p) => p.length > 0);
  const assetsMap =
    customAssetsMap || (await getAssetsMapForBot(selectedImageCollections));

  for (const part of parts) {
    const segments = parseMessageSegmentsByImageTokens(part, assetsMap);
    for (const seg of segments) {
      if (seg.type === "text") {
        const textChunks = chunkTextByLength(seg.text || "", 1000);
        for (const chunk of textChunks) {
          await axios.post(
            `https://graph.facebook.com/${META_GRAPH_API_VERSION}/${instagramSenderId}/messages`,
            {
              recipient: { id: recipientId },
              message: { text: chunk },
            },
            {
              params: { access_token: accessToken },
              headers: { "Content-Type": "application/json" },
            },
          );
        }
        continue;
      }

      if (seg.type === "image" && seg.url) {
        await axios.post(
          `https://graph.facebook.com/${META_GRAPH_API_VERSION}/${instagramSenderId}/messages`,
          {
            recipient: { id: recipientId },
            message: {
              attachment: {
                type: "image",
                payload: { url: seg.url, is_reusable: true },
              },
            },
          },
          {
            params: { access_token: accessToken },
            headers: { "Content-Type": "application/json" },
          },
        );
      }
    }
  }
}

async function sendWhatsAppImageByUrl(
  recipientId,
  imageUrl,
  accessToken,
  phoneNumberId,
  caption = "",
) {
  if (!recipientId || !imageUrl || !accessToken || !phoneNumberId) {
    return;
  }

  const payload = {
    messaging_product: "whatsapp",
    recipient_type: "individual",
    to: recipientId,
    type: "image",
    image: {
      link: imageUrl,
    },
  };
  const trimmedCaption =
    typeof caption === "string" ? caption.trim().slice(0, 1024) : "";
  if (trimmedCaption) {
    payload.image.caption = trimmedCaption;
  }

  await axios.post(
    `https://graph.facebook.com/${META_GRAPH_API_VERSION}/${phoneNumberId}/messages`,
    payload,
    {
      headers: {
        Authorization: `Bearer ${accessToken}`,
        "Content-Type": "application/json",
      },
    },
  );
}

async function sendWhatsAppMessage(
  recipientId,
  message,
  accessToken,
  phoneNumberId,
  options = {},
  customAssetsMap = null,
) {
  const { selectedImageCollections = null } = options || {};
  const normalizedMessage = normalizeOutgoingText(message);
  if (!normalizedMessage || !accessToken || !phoneNumberId || !recipientId) {
    return;
  }

  const parts = String(normalizedMessage || "")
    .split("[cut]")
    .map((p) => p.trim())
    .filter((p) => p.length > 0);
  const assetsMap =
    customAssetsMap || (await getAssetsMapForBot(selectedImageCollections));

  for (const part of parts) {
    const segments = parseMessageSegmentsByImageTokens(part, assetsMap);
    for (const seg of segments) {
      if (seg.type === "text") {
        const textChunks = chunkTextByLength(seg.text || "", 4096);
        for (const chunk of textChunks) {
          await axios.post(
            `https://graph.facebook.com/${META_GRAPH_API_VERSION}/${phoneNumberId}/messages`,
            {
              messaging_product: "whatsapp",
              recipient_type: "individual",
              to: recipientId,
              type: "text",
              text: {
                preview_url: false,
                body: chunk,
              },
            },
            {
              headers: {
                Authorization: `Bearer ${accessToken}`,
                "Content-Type": "application/json",
              },
            },
          );
        }
        continue;
      }

      if (seg.type === "image" && seg.url) {
        try {
          await sendWhatsAppImageByUrl(
            recipientId,
            seg.url,
            accessToken,
            phoneNumberId,
            seg.alt || "",
          );
        } catch (imageError) {
          const fallback = `[ไม่สามารถส่งรูป ${seg.label || "image"}]`;
          await axios.post(
            `https://graph.facebook.com/${META_GRAPH_API_VERSION}/${phoneNumberId}/messages`,
            {
              messaging_product: "whatsapp",
              recipient_type: "individual",
              to: recipientId,
              type: "text",
              text: { body: fallback },
            },
            {
              headers: {
                Authorization: `Bearer ${accessToken}`,
                "Content-Type": "application/json",
              },
            },
          );
          console.warn(
            "[WhatsApp] ส่งรูปไม่สำเร็จ:",
            imageError?.response?.data || imageError?.message || imageError,
          );
        }
      }
    }
  }
}

async function fetchWhatsAppMediaAsBase64(mediaId, accessToken) {
  if (!mediaId || !accessToken) {
    throw new Error("missing media id or access token");
  }

  const metaResponse = await axios.get(
    `https://graph.facebook.com/${META_GRAPH_API_VERSION}/${encodeURIComponent(
      mediaId,
    )}`,
    {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    },
  );

  const mediaUrl = metaResponse?.data?.url;
  const mimeType =
    metaResponse?.data?.mime_type ||
    metaResponse?.data?.mimeType ||
    "application/octet-stream";
  if (!mediaUrl) {
    throw new Error("whatsapp media url not found");
  }

  const mediaResponse = await axios.get(mediaUrl, {
    responseType: "arraybuffer",
    headers: {
      Authorization: `Bearer ${accessToken}`,
    },
  });

  let buffer = Buffer.from(mediaResponse.data);
  let finalMime = mimeType;

  if (typeof mimeType === "string" && mimeType.startsWith("image/")) {
    try {
      buffer = await sharp(buffer)
        .resize({
          width: 1024,
          height: 1024,
          fit: "inside",
          withoutEnlargement: true,
        })
        .jpeg({ quality: 85, progressive: true })
        .toBuffer();
      finalMime = "image/jpeg";
    } catch (imageError) {
      console.warn(
        "[WhatsApp] ไม่สามารถแปลงขนาดรูปจาก media API ได้:",
        imageError?.message || imageError,
      );
    }
  }

  return {
    base64: buffer.toString("base64"),
    mimeType: finalMime,
  };
}

// Helper: read local asset buffer robustly (handle ext variants and URL fallback)
async function readInstructionAssetBuffer(seg) {
  const label = seg.label || "";
  const requestedFileName = seg.fileName || "";
  let assetDoc = null;

  try {
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("instruction_assets");

    if (label) {
      // ค้นหาด้วย label ก่อน (รองรับทั้งภาษาไทยและอังกฤษ)
      assetDoc = await coll.findOne({ label });

      // ถ้าไม่เจอ ลองค้นหาด้วย slug (กรณีที่ส่ง slug มาแทน label)
      if (!assetDoc) {
        assetDoc = await coll.findOne({ slug: label });
      }
    }
    if (!assetDoc && requestedFileName) {
      assetDoc = await coll.findOne({
        $or: [
          { fileName: requestedFileName },
          { thumbFileName: requestedFileName },
        ],
      });
    }

    if (assetDoc) {
      const bucket = new GridFSBucket(db, { bucketName: "instructionAssets" });
      const baseName = getInstructionAssetBaseName(assetDoc);
      const mainFileNames = Array.from(
        new Set(
          [
            assetDoc.fileName,
            ...buildInstructionAssetVariantFilenames(baseName, "main"),
          ]
            .filter((name) => typeof name === "string" && name.trim())
            .map((name) => name.trim()),
        ),
      );
      const thumbFileNames = Array.from(
        new Set(
          [
            assetDoc.thumbFileName,
            ...buildInstructionAssetVariantFilenames(baseName, "thumb"),
          ]
            .filter((name) => typeof name === "string" && name.trim())
            .map((name) => name.trim()),
        ),
      );
      const useThumb =
        requestedFileName &&
        (requestedFileName === assetDoc.thumbFileName ||
          /_thumb\.(jpe?g)$/i.test(requestedFileName));
      const candidateFileNames = useThumb ? thumbFileNames : mainFileNames;
      const targetId = useThumb ? assetDoc.thumbFileId : assetDoc.fileId;
      if (!candidateFileNames.length) {
        throw new Error("ไม่พบชื่อไฟล์ของรูปภาพที่ต้องการใช้งาน");
      }
      let resolvedFileName = candidateFileNames[0];
      let downloadStream = null;

      if (targetId) {
        const objectId = toObjectId(targetId);
        if (objectId) {
          downloadStream = bucket.openDownloadStream(objectId);
        }
      }

      if (!downloadStream) {
        for (const name of candidateFileNames) {
          try {
            downloadStream = bucket.openDownloadStreamByName(name);
            resolvedFileName = name;
            break;
          } catch (err) {
            const isFileNotFound =
              err?.code === "FileNotFound" ||
              err?.code === 26 ||
              err?.message?.includes("File not found") ||
              err?.message?.includes("FileNotFound");
            if (!isFileNotFound) {
              throw err;
            }
          }
        }
        if (!downloadStream) {
          throw new Error("ไม่พบไฟล์รูปภาพในระบบจัดเก็บ");
        }
      }

      const buffer = await streamToBuffer(downloadStream);
      let contentType = assetDoc.mime || "image/jpeg";
      if (!assetDoc.mime) {
        const ext = path.extname(resolvedFileName).toLowerCase();
        if (ext === ".png") contentType = "image/png";
        else if (ext === ".webp") contentType = "image/webp";
      }

      return {
        buffer,
        filename: resolvedFileName,
        contentType,
      };
    }
  } catch (err) {
    console.warn(
      "[Assets] read buffer from MongoDB failed, fallback to filesystem/url:",
      err?.message || err,
    );
  }

  const baseDir = ASSETS_DIR;
  const tryFilesSet = new Set();
  const addFileName = (name) => {
    if (!name || typeof name !== "string") return;
    const trimmed = name.trim();
    if (!trimmed) return;
    tryFilesSet.add(trimmed);
  };
  const addBaseVariants = (base) => {
    if (!base || typeof base !== "string") return;
    const trimmed = base.trim();
    if (!trimmed) return;
    addFileName(`${trimmed}.jpg`);
    addFileName(`${trimmed}.jpeg`);
    addFileName(`${trimmed}.png`);
    addFileName(`${trimmed}.webp`);
    addFileName(`${trimmed}_thumb.jpg`);
    addFileName(`${trimmed}_thumb.jpeg`);
  };

  addFileName(requestedFileName);
  addBaseVariants(label);
  const segSlug =
    typeof seg.slug === "string" && seg.slug.trim() ? seg.slug.trim() : null;
  addBaseVariants(segSlug);
  if (label) {
    addBaseVariants(generateSlugFromLabel(label));
  }

  const tryFiles = Array.from(tryFilesSet);

  for (const name of tryFiles) {
    const p = path.join(baseDir, name);
    try {
      if (fs.existsSync(p)) {
        const b = fs.readFileSync(p);
        const ext = path.extname(p).toLowerCase().replace(".", "") || "jpg";
        const ct =
          ext === "png"
            ? "image/png"
            : ext === "webp"
              ? "image/webp"
              : "image/jpeg";
        return { buffer: b, filename: name, contentType: ct };
      }
    } catch (_) {
      /* ignore */
    }
  }

  if (seg.url) {
    const resp = await axios.get(seg.url, { responseType: "arraybuffer" });
    const b = Buffer.from(resp.data);
    const urlExt = (seg.url.split(".").pop() || "jpg").toLowerCase();
    const ct = urlExt.startsWith("png")
      ? "image/png"
      : urlExt.startsWith("webp")
        ? "image/webp"
        : "image/jpeg";
    return {
      buffer: b,
      filename: seg.fileName || `${label || "image"}.jpg`,
      contentType: ct,
    };
  }

  throw new Error(
    "อ่านไฟล์รูปภาพไม่สำเร็จ: ไม่พบไฟล์ในระบบและไม่มี URL ให้ดึง",
  );
}

// Helper to download and optimize Facebook image to base64
async function fetchFacebookImageAsBase64(url) {
  const response = await axios.get(url, { responseType: "arraybuffer" });
  let buffer = Buffer.from(response.data, "binary");
  try {
    buffer = await sharp(buffer)
      .resize({
        width: 1024,
        height: 1024,
        fit: "inside",
        withoutEnlargement: true,
      })
      .jpeg({ quality: 85, progressive: true })
      .toBuffer();
  } catch (err) {
    console.error("Error processing Facebook image:", err.message);
  }
  return buffer.toString("base64");
}

// Convert table instruction data to a JSON string
function tableInstructionToJSON(instruction) {
  if (!instruction || instruction.type !== "table") return "";

  const columns = Array.isArray(instruction?.data?.columns)
    ? instruction.data.columns
    : [];
  const rowSource = Array.isArray(instruction?.data?.rows)
    ? instruction.data.rows
    : [];

  const normalizedColumns = columns.map((col) => {
    if (col === null || col === undefined) return "";
    return String(col);
  });

  const normalizedRows = rowSource.map((row) => {
    if (Array.isArray(row)) {
      return row.map((cell) => {
        if (cell === null || cell === undefined) return "";
        return String(cell).replace(/\r\n/g, "\n");
      });
    }
    if (row && typeof row === "object") {
      return normalizedColumns.map((col, idx) => {
        const key = col && col.trim() ? col : `column_${idx + 1}`;
        const value = row[col] ?? row[key] ?? row[idx] ?? "";
        return String(value).replace(/\r\n/g, "\n");
      });
    }
    return [String(row ?? "")];
  });

  const toIsoString = (value) => {
    if (!value) return undefined;
    try {
      const date = value instanceof Date ? value : new Date(value);
      if (Number.isNaN(date.getTime())) return undefined;
      return date.toISOString();
    } catch {
      return undefined;
    }
  };

  const payload = {
    instructionId:
      instruction.instructionId ||
      (instruction._id ? instruction._id.toString() : undefined),
    version: Number.isInteger(instruction.version)
      ? instruction.version
      : undefined,
    type: "table",
    title: instruction.title || undefined,
    content: instruction.content || undefined,
    createdAt: toIsoString(instruction.createdAt),
    updatedAt: toIsoString(instruction.updatedAt),
    data: {
      columns: normalizedColumns,
      rows: normalizedRows,
    },
  };

  if (!payload.instructionId) {
    delete payload.instructionId;
  }
  if (!payload.title || !payload.title.trim()) {
    delete payload.title;
  }
  if (!payload.content || !payload.content.trim()) {
    delete payload.content;
  }
  if (!payload.createdAt) {
    delete payload.createdAt;
  }
  if (!payload.updatedAt) {
    delete payload.updatedAt;
  }
  if (payload.version === undefined) {
    delete payload.version;
  }

  return JSON.stringify(payload, null, 2);
}

// Build system prompt text from selected instruction libraries
function buildSystemPromptFromLibraries(libraries) {
  const allInstructions = libraries.flatMap((lib) => lib.instructions || []);
  const parts = allInstructions
    .map((inst) => {
      if (inst.type === "table") {
        return tableInstructionToJSON(inst);
      }
      return inst.content || "";
    })
    .filter((text) => text && text.trim() !== "");
  return parts.join("\n\n");
}

// Helper function to process Facebook message with AI
async function processFacebookMessageWithAI(
  contentSequence,
  userId,
  facebookBot,
) {
  try {
    const client = await connectDB();
    const db = client.db("chatbot");

    const aiModel = facebookBot.aiModel || "gpt-5";

    let systemPrompt = "คุณเป็น AI Assistant ที่ช่วยตอบคำถามผู้ใช้";
    const fbSelections = normalizeInstructionSelections(
      facebookBot.selectedInstructions || [],
    );
    const fbRuntimeInstructionContext = await resolveInstructionMetaForRuntime(
      fbSelections,
      null,
      { policy: "latest_only" },
    );
    if (fbRuntimeInstructionContext.promptSelections.length > 0) {
      const prompt = await buildSystemPromptFromSelections(
        fbRuntimeInstructionContext.promptSelections,
        db,
      );
      if (prompt.trim()) {
        systemPrompt = prompt.trim();
      }
    }

    // เพิ่มคำแนะนำเกี่ยวกับการแทรกรูปภาพด้วยแท็ก #[IMAGE:<label>]
    const assetsText = await getAssetsInstructionsText();
    if (assetsText) {
      systemPrompt = `${systemPrompt}\n\n${assetsText}`;
    }

    const history = await getAIHistory(userId);

    const recoveryStrategies = [
      { key: "original", label: "ข้อมูลเดิมทั้งหมด" },
      { key: "drop_invalid_images", label: "ลบรูปภาพที่อาจมีปัญหา" },
      { key: "recent_text_only", label: "ใช้เฉพาะข้อความล่าสุดที่ใช้ได้" },
    ];

    const baseSequence = Array.isArray(contentSequence)
      ? contentSequence
      : [];

    let assistantReply = "";

    for (
      let attemptIndex = 0;
      attemptIndex < recoveryStrategies.length && !assistantReply;
      attemptIndex++
    ) {
      const strategy = recoveryStrategies[attemptIndex];
      const { sequence: sanitizedSequence, textParts, meta } =
        filterContentSequenceForStrategy(baseSequence, strategy.key);

      if (!sanitizedSequence.length) {
        console.warn(
          `[Facebook AI] กลยุทธ์ "${strategy.label}" ไม่มีข้อมูลสำหรับผู้ใช้ ${userId} ข้ามไปยังกลยุทธ์ถัดไป`,
        );
        continue;
      }

      const hasImages = sanitizedSequence.some((item) => item.type === "image");
      const combinedText = textParts.join("\n\n");

      if (!hasImages && !combinedText) {
        console.warn(
          `[Facebook AI] กลยุทธ์ "${strategy.label}" ไม่เหลือข้อความหรือรูปภาพหลังจัดการสำหรับผู้ใช้ ${userId}`,
        );
        continue;
      }

      if (
        meta.droppedImages > 0 ||
        meta.droppedTexts > 0 ||
        meta.droppedOthers > 0 ||
        meta.suspectImages > 0
      ) {
        const adjustments = [];
        if (meta.droppedImages > 0) {
          adjustments.push(`ลบรูปภาพ ${meta.droppedImages} รายการ`);
        }
        if (meta.suspectImages > 0) {
          adjustments.push(`พบรูปภาพที่ต้องจับตา ${meta.suspectImages} รายการ`);
        }
        if (meta.droppedTexts > 0) {
          adjustments.push(`ลบข้อความ ${meta.droppedTexts} รายการ`);
        }
        if (meta.droppedOthers > 0) {
          adjustments.push(`ละเว้นข้อมูลอื่น ${meta.droppedOthers} รายการ`);
        }
        console.log(
          `[Facebook AI] กลยุทธ์ "${strategy.label}" ปรับข้อมูล: ${adjustments.join(", ")}`,
        );
      }

      if (hasImages) {
        const imageCount = sanitizedSequence.filter((i) => i.type === "image").length;
        console.log(
          `[Facebook AI] ประมวลผลแบบ multimodal (กลยุทธ์ ${strategy.label}, รอบที่ ${attemptIndex + 1}/${recoveryStrategies.length}) ภาพ ${imageCount} รูป`,
        );
        assistantReply = await getAssistantResponseMultimodal(
          systemPrompt,
          history,
          sanitizedSequence,
          aiModel,
          facebookBot._id.toString(),
          "facebook",
          userId
        );
      } else {
        const preview = combinedText.substring(0, 100);
        console.log(
          `[Facebook AI] ประมวลผลข้อความ (กลยุทธ์ ${strategy.label}, รอบที่ ${attemptIndex + 1}/${recoveryStrategies.length}): ${preview}${combinedText.length > 100 ? "..." : ""}`,
        );
        assistantReply = await getAssistantResponseTextOnly(
          systemPrompt,
          history,
          combinedText,
          aiModel,
          facebookBot._id.toString(),
          "facebook",
          userId
        );
      }

      if (!assistantReply) {
        console.warn(
          `[Facebook AI] กลยุทธ์ "${strategy.label}" ไม่สามารถสร้างคำตอบสำหรับผู้ใช้ ${userId}`,
        );
      }
    }

    assistantReply = await filterMessage(assistantReply);

    // ดึงข้อความจากแท็ก THAI_REPLY ถ้ามี
    const finalReply = extractThaiReply(assistantReply);

    await saveChatHistory(
      userId,
      contentSequence,
      assistantReply,
      "facebook",
      facebookBot._id ? facebookBot._id.toString() : null,
      fbRuntimeInstructionContext.instructionRefs,
      facebookBot.name || null,
      { instructionMeta: fbRuntimeInstructionContext.instructionMeta },
    );

    return finalReply.trim();
  } catch (error) {
    console.error("Error processing Facebook message with AI:", error);
    return "";
  }
}

// Helper function to process message with AI
async function processMessageWithAI(message, userId, lineBot) {
  const aiModel = lineBot.aiModel || "gpt-5";
  const lineSelections = normalizeInstructionSelections(
    lineBot.selectedInstructions || [],
  );

  let systemPrompt = "คุณเป็น AI Assistant ที่ช่วยตอบคำถามผู้ใช้";

  try {
    const client = await connectDB();
    const db = client.db("chatbot");

    if (lineSelections.length > 0) {
      const prompt = await buildSystemPromptFromSelections(lineSelections, db);
      if (prompt.trim()) {
        systemPrompt = prompt.trim();
      }
    }

    const lineBotId = lineBot?._id ? lineBot._id.toString() : null;
    const apiKeyToUse = await getOpenAIApiKeyForBot(lineBotId, "line");
    if (!apiKeyToUse.apiKey) {
      console.warn("[Line AI] No API key available");
      return "";
    }
    const openai = buildLLMClientFromKey(apiKeyToUse);
    if (!openai) {
      console.warn("[Line AI] Cannot create client for selected provider");
      return "";
    }
    const resolvedModel = resolveModelForProvider(aiModel, apiKeyToUse.provider);
    if (!resolvedModel.ok) {
      console.warn(`[Line AI] ${resolvedModel.error}`);
      return "";
    }

    const messageVariants = [
      {
        label: "ต้นฉบับ",
        content: sanitizeTextValue(message, { maxLength: 8000 }),
      },
      {
        label: "ตัดครึ่งท้าย",
        content: sanitizeTextValue(message, {
          maxLength: 4000,
          keepTail: true,
        }),
      },
    ].filter((variant, index, arr) => {
      if (!variant.content) {
        return false;
      }
      if (index === 0) {
        return true;
      }
      return variant.content !== arr[index - 1].content;
    });

    if (messageVariants.length === 0) {
      console.warn(
        `[Line AI] ข้อความของผู้ใช้ ${userId} ไม่มีเนื้อหาที่สามารถส่งให้ AI ประมวลผลได้`,
      );
      return "";
    }

    for (let attemptIndex = 0; attemptIndex < messageVariants.length; attemptIndex++) {
      const variant = messageVariants[attemptIndex];
      const payloadMessages = [
        { role: "system", content: systemPrompt },
        { role: "user", content: variant.content },
      ];

      try {
        console.log(
          `[Line AI] ประมวลผลข้อความ (${variant.label}, รอบที่ ${attemptIndex + 1}/${messageVariants.length}) สำหรับผู้ใช้ ${userId}`,
        );
        const aiConfig = normalizeAiConfig(lineBot.aiConfig || {});
        const payload = {
          model: resolvedModel.model,
          messages: payloadMessages,
        };
        if (aiConfig.apiMode === "responses" && aiConfig.reasoningEffort) {
          payload.reasoning_effort = aiConfig.reasoningEffort;
        }
        if (aiConfig.apiMode === "chat") {
          if (aiConfig.temperature !== null) payload.temperature = aiConfig.temperature;
          if (aiConfig.topP !== null) payload.top_p = aiConfig.topP;
          if (aiConfig.presencePenalty !== null) payload.presence_penalty = aiConfig.presencePenalty;
          if (aiConfig.frequencyPenalty !== null) payload.frequency_penalty = aiConfig.frequencyPenalty;
        }

        const response = await openai.chat.completions.create(payload);

        let assistantReply = response.choices[0].message.content;
        if (typeof assistantReply !== "string") {
          assistantReply = JSON.stringify(assistantReply);
        }

        if (response.usage) {
          const usage = response.usage;
          const tokenInfo = `\n\n📊 Token Usage: ${usage.prompt_tokens} input + ${usage.completion_tokens} output = ${usage.total_tokens} total tokens`;
          assistantReply += tokenInfo;
        }

        const finalReply = extractThaiReply(assistantReply);
        return finalReply.trim();
      } catch (error) {
        console.error(
          `[Line AI] เกิดข้อผิดพลาดระหว่างประมวลผล (${variant.label}, รอบที่ ${attemptIndex + 1}/${messageVariants.length}):`,
          error,
        );
      }
    }

    return "";
  } catch (error) {
    console.error("Error preparing AI request:", error);
    return "";
  }

}

