// Route: อัปเดต keyword settings สำหรับ Line Bot
app.put("/api/line-bots/:id/keywords", async (req, res) => {
  try {
    const { id } = req.params;
    const { keywordSettings } = req.body;

    if (!keywordSettings || typeof keywordSettings !== "object") {
      return res.status(400).json({ error: "keywordSettings ต้องเป็น object" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("line_bots");

    // รองรับทั้งรูปแบบเก่า (string) และใหม่ (object with keyword, response, sendResponse)
    const normalizeKeywordSetting = (setting) => {
      if (!setting) return { keyword: "", response: "", sendResponse: false };
      if (typeof setting === "string") {
        return { keyword: setting.trim(), response: "", sendResponse: false };
      }
      const response = (setting.response || "").trim();
      const sendResponseValue = parseOptionalBoolean(setting.sendResponse);
      return {
        keyword: (setting.keyword || "").trim(),
        response,
        sendResponse:
          typeof sendResponseValue === "boolean"
            ? sendResponseValue
            : response.length > 0,
      };
    };

    const disableAINormalized = normalizeKeywordSetting(keywordSettings.disableAI);
    const rawAlsoDisableFollowUp = keywordSettings.disableAI?.alsoDisableFollowUp;
    disableAINormalized.alsoDisableFollowUp = typeof rawAlsoDisableFollowUp === "boolean"
      ? rawAlsoDisableFollowUp
      : true;

    const normalizedSettings = {
      enableAI: normalizeKeywordSetting(keywordSettings.enableAI),
      disableAI: disableAINormalized,
      disableFollowUp: normalizeKeywordSetting(keywordSettings.disableFollowUp),
    };

    const result = await coll.updateOne(
      { _id: new ObjectId(id) },
      {
        $set: {
          keywordSettings: normalizedSettings,
          updatedAt: new Date(),
        },
      },
    );

    if (result.matchedCount === 0) {
      return res.status(404).json({ error: "ไม่พบ Line Bot ที่ระบุ" });
    }

    res.json({
      message: "อัปเดต keyword settings เรียบร้อยแล้ว",
      keywordSettings: normalizedSettings,
    });
  } catch (err) {
    console.error("Error updating line bot keyword settings:", err);
    res.status(500).json({ error: "ไม่สามารถอัปเดต keyword settings ได้" });
  }
});

