app.post("/admin/broadcast", broadcastUpload, async (req, res) => {
  try {
    let { messages, audience, channels, settings } = req.body;

    // Parse JSON fields if multipart
    const parseJSON = (val) => {
      if (typeof val === "string") {
        try {
          return JSON.parse(val);
        } catch (e) {
          return val;
        }
      }
      return val;
    };

    messages = parseJSON(messages);
    channels = parseJSON(channels);
    audience = parseJSON(audience);
    settings = parseJSON(settings);

    // Default settings if not provided
    settings = {
      batchSize: parseInt(settings?.batchSize || 10),
      batchDelay: parseInt(settings?.batchDelay || 60),
      messageDelay: parseFloat(settings?.messageDelay || 1)
    };

    if (!messages || !channels || channels.length === 0) {
      throw new Error("กรุณากรอกข้อความและเลือกช่องทาง");
    }

    // Wrap single message if legacy format (string)
    if (typeof messages === 'string') {
      messages = [{ type: 'text', content: messages }];
    }

    // Process uploaded images
    if (req.files && req.files.length > 0) {
      const client = await connectDB();
      const db = client.db("chatbot");
      const bucket = new GridFSBucket(db, { bucketName: "broadcastAssets" });
      const { Readable } = require("stream");

      let fileIndex = 0;
      for (let i = 0; i < messages.length; i++) {
        if (
          messages[i].type === "image" &&
          !messages[i].url &&
          fileIndex < req.files.length
        ) {
          const file = req.files[fileIndex++];
          const safeName = file.originalname.replace(/[^a-zA-Z0-9._-]/g, "_");
          const filename = `broadcast-${Date.now()}-${safeName}`;

          // Upload to GridFS
          await new Promise((resolve, reject) => {
            const uploadStream = bucket.openUploadStream(filename, {
              contentType: file.mimetype,
            });
            const bufferStream = new Readable();
            bufferStream.push(file.buffer);
            bufferStream.push(null);

            bufferStream
              .pipe(uploadStream)
              .on("error", reject)
              .on("finish", () => resolve());
          });

          // Set URL (must be absolute for LINE/Facebook)
          const urlBase = PUBLIC_BASE_URL ? PUBLIC_BASE_URL.replace(/\/$/, "") : "";
          messages[i].url = `${urlBase}/broadcast/assets/${filename}`;
        }
      }
    }

    // Get targets
    const users = await getBroadcastAudience(channels, audience);
    if (users.length === 0) {
      return res.json({ success: false, error: "ไม่พบกลุ่มเป้าหมายตามเงื่อนไขที่เลือก" });
    }

    // Build channelInfo (bot names for per-channel progress display)
    const channelInfoMap = {};
    const collMap2 = { line: "line_bots", facebook: "facebook_bots", instagram: "instagram_bots", whatsapp: "whatsapp_bots" };
    const dbForInfo = (await connectDB()).db("chatbot");
    const uniqueChannels = new Set(users.map(u => `${u.platform}:${u.botId}`));
    for (const chKey of uniqueChannels) {
      const [plat, bId] = chKey.split(":");
      const collName = collMap2[plat];
      let name = chKey;
      if (collName && ObjectId.isValid(bId)) {
        const b = await dbForInfo.collection(collName).findOne({ _id: new ObjectId(bId) });
        if (b) name = b.name || b.pageName || chKey;
      }
      channelInfoMap[chKey] = { name, platform: plat };
    }

    // Create Job
    const jobId = new ObjectId().toString();
    const job = new BroadcastQueue(
      jobId,
      { messages, targets: users, channels },
      settings,
      channelInfoMap,
    );

    activeBroadcasts.set(jobId, job);

    // Start in background
    job.start();

    res.json({ success: true, broadcastId: jobId, count: users.length });
  } catch (err) {
    console.error("Broadcast failed:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

