// ═══════════════════════ Version Management API ═══════════════════════

// GET versions for an instruction
app.get("/api/instruction-ai/versions/:instructionId", requireAdmin, async (req, res) => {
  try {
    const { instructionId } = req.params;
    const client = await connectDB();
    const db = client.db("chatbot");

    // Get current instruction
    const inst = ObjectId.isValid(instructionId)
      ? await db.collection("instructions_v2").findOne({ _id: new ObjectId(instructionId) })
      : null;

    const instId = inst?.instructionId || instructionId;
    const currentVersion = Number.isInteger(inst?.version) ? inst.version : 0;

    // Get all version snapshots
    const versions = await db.collection("instruction_versions")
      .find({ instructionId: instId })
      .sort({ version: -1 })
      .project({ version: 1, snapshotAt: 1, note: 1 })
      .toArray();

    res.json({
      currentVersion,
      versions: versions.map(v => ({
        version: v.version,
        snapshotAt: v.snapshotAt,
        note: v.note || "",
      })),
    });
  } catch (error) {
    console.error("[Versions] List error:", error);
    res.status(500).json({ error: error.message });
  }
});

// POST save a new version
app.post("/api/instruction-ai/versions/:instructionId", requireAdmin, async (req, res) => {
  try {
    const { instructionId } = req.params;
    const { note = "" } = req.body;
    const client = await connectDB();
    const db = client.db("chatbot");

    const inst = ObjectId.isValid(instructionId)
      ? await db.collection("instructions_v2").findOne({ _id: new ObjectId(instructionId) })
      : null;

    if (!inst) return res.status(404).json({ error: "ไม่พบ Instruction" });

    const instId = inst.instructionId || instructionId;
    const versionColl = db.collection("instruction_versions");

    // Find next version number
    const latest = await versionColl.find({ instructionId: instId })
      .sort({ version: -1 }).limit(1).toArray();
    const nextVersion = latest.length > 0 ? (latest[0].version || 0) + 1 : 1;

    // Create snapshot
    const snapshot = {
      instructionId: instId,
      version: nextVersion,
      name: inst.name || "",
      description: inst.description || "",
      dataItems: (inst.dataItems || []).map(item => {
        const copy = { itemId: item.itemId, title: item.title, type: item.type };
        if (item.type === "table" && item.data) {
          copy.data = {
            columns: item.data.columns || [],
            rows: item.data.rows || [],
            rowCount: Array.isArray(item.data.rows) ? item.data.rows.length : 0,
          };
        } else if (item.type === "text") {
          copy.content = item.content || "";
        }
        return copy;
      }),
      conversationStarter: normalizeConversationStarterConfig(
        inst.conversationStarter,
      ),
      note: (note || "").substring(0, 500),
      snapshotAt: new Date(),
      savedBy: "admin_ui",
    };

    await versionColl.updateOne(
      { instructionId: instId, version: nextVersion },
      { $set: snapshot },
      { upsert: true }
    );

    // Update instruction's version number
    await db.collection("instructions_v2").updateOne(
      { _id: new ObjectId(instructionId) },
      { $set: { version: nextVersion, updatedAt: new Date() } }
    );
    invalidateInstructionPromptCaches();

    res.json({
      success: true,
      version: nextVersion,
      note: snapshot.note,
      snapshotAt: snapshot.snapshotAt,
    });
  } catch (error) {
    console.error("[Versions] Save error:", error);
    res.status(500).json({ error: error.message });
  }
});

// ─── InstructionAI Responses API Helpers ───
const INSTRUCTION_REASONING_SUPPORT = {
  "gpt-5.2": { efforts: ["none", "low", "medium", "high", "xhigh"], default: "none" },
  "gpt-5.2-codex": { efforts: ["none", "low", "medium", "high", "xhigh"], default: "none" },
  "gpt-5.1": { efforts: ["none", "low", "medium", "high"], default: "none" },
  "gpt-5": { efforts: ["low", "medium", "high"], default: "medium" },
};

const INSTRUCTION_THINKING_MAP = { off: "none", low: "low", medium: "medium", high: "high", max: "xhigh" };
const INSTRUCTION_MAX_TOOL_ITERATIONS = (() => {
  const raw = Number.parseInt(process.env.INSTRUCTION_MAX_TOOL_ITERATIONS || "30", 10);
  if (!Number.isFinite(raw)) return 30;
  return Math.min(60, Math.max(4, raw));
})();

function resolveInstructionReasoningEffort(model, thinking) {
  const normalizedModelId =
    typeof model === "string" && model.includes("/")
      ? model.split("/").pop()
      : model;
  const modelConfig =
    INSTRUCTION_REASONING_SUPPORT[normalizedModelId] ||
    INSTRUCTION_REASONING_SUPPORT["gpt-5.2"];
  let effort = INSTRUCTION_THINKING_MAP[thinking] || modelConfig.default;
  if (!modelConfig.efforts.includes(effort)) effort = modelConfig.default;
  return effort;
}

function hasInstructionAssistantText(messages) {
  if (!Array.isArray(messages)) return false;
  return messages.some((msg) =>
    msg &&
    msg.role === "assistant" &&
    typeof msg.content === "string" &&
    msg.content.trim().length > 0
  );
}

function getInstructionFinalTextFallback(toolsUsed = []) {
  const toolCount = Array.isArray(toolsUsed) ? toolsUsed.length : 0;
  if (toolCount > 0) {
    return "⌛ โมเดลยังไม่ส่งข้อความสรุปสุดท้าย แต่ประมวลผลเครื่องมือเรียบร้อยแล้ว กรุณาพิมพ์ \"สรุปผลล่าสุด\" อีกครั้ง";
  }
  return "⌛ โมเดลยังไม่ส่งข้อความสรุปสุดท้าย กรุณาลองส่งคำถามเดิมอีกครั้ง";
}

function canUseInstructionPreviousResponseId(provider) {
  return normalizeProvider(provider) === LLM_PROVIDER_OPENAI;
}

function buildInstructionStatelessFunctionCallInput(call) {
  if (!call || !call.call_id || !call.name) return null;
  return {
    type: "function_call",
    call_id: call.call_id,
    name: call.name,
    arguments:
      typeof call.arguments === "string"
        ? call.arguments
        : JSON.stringify(call.arguments || {}),
  };
}

function appendInstructionTurnToStatelessInput(input, options = {}) {
  if (!Array.isArray(input)) return;
  const {
    assistantText = "",
    toolCalls = [],
    toolOutputs = [],
  } = options || {};

  if (typeof assistantText === "string" && assistantText.trim()) {
    input.push({ role: "assistant", content: assistantText.trim() });
  }

  for (const call of Array.isArray(toolCalls) ? toolCalls : []) {
    const mapped = buildInstructionStatelessFunctionCallInput(call);
    if (mapped) input.push(mapped);
  }

  if (Array.isArray(toolOutputs) && toolOutputs.length > 0) {
    input.push(...toolOutputs);
  }
}

async function requestInstructionFinalSummaryWithoutTools(openai, options = {}) {
  const {
    model = "gpt-5.2",
    previousResponseId = null,
    effort = "low",
    toolsUsed = [],
    stateful = true,
    conversationInput = [],
  } = options || {};

  const normalizedEffort = effort === "xhigh" ? "high" : (effort === "none" ? "low" : effort);
  const recentTools = Array.isArray(toolsUsed) ? toolsUsed.slice(-6) : [];
  const toolContext = recentTools.length > 0
    ? recentTools
      .map((tool, idx) => {
        const name = tool?.tool || "tool";
        const summary = typeof tool?.summary === "string" ? tool.summary.trim() : "";
        return `${idx + 1}. ${name}${summary ? ` — ${summary}` : ""}`;
      })
      .join("\n")
    : "ไม่มี";

  const promptInput = [
    {
      role: "user",
      content: [
        {
          type: "input_text",
          text: [
            "สรุปคำตอบสุดท้ายให้ผู้ใช้จากบริบทก่อนหน้า",
            "ห้ามเรียกใช้เครื่องมือเพิ่ม",
            "ถ้ามีการแก้ไขข้อมูล ให้สรุปรายการที่เปลี่ยนแปลงสั้น ๆ",
            `บริบทเครื่องมือล่าสุด:\n${toolContext}`,
          ].join("\n\n"),
        },
      ],
    },
  ];

  const payload = {
    model,
    tools: [],
    reasoning: { effort: normalizedEffort },
    input:
      stateful || !Array.isArray(conversationInput) || conversationInput.length === 0
        ? promptInput
        : [...conversationInput, ...promptInput],
  };
  if (stateful && previousResponseId) {
    payload.previous_response_id = previousResponseId;
  }

  const response = await openai.responses.create(payload);
  return {
    responseId: response?.id || null,
    usage: mapInstructionResponseUsage(response?.usage),
    content: extractInstructionResponseText(response).trim(),
  };
}

function sanitizeInstructionVersionNote(note) {
  if (!note) return "";
  let text = String(note)
    .replace(/\r\n/g, "\n")
    .split("\n")
    .map((line) => line.trim())
    .filter(Boolean)
    .join(" ");

  text = text
    .replace(/^["'`]+/, "")
    .replace(/["'`]+$/, "")
    .replace(/\s+/g, " ")
    .trim();

  if (!text) return "";
  return text.substring(0, 180);
}

async function generateInstructionVersionNoteWithModel(openai, options = {}) {
  const {
    model = "gpt-5.2",
    previousResponseId = null,
    effort = "low",
    toolsUsed = [],
    changes = [],
    finalContent = "",
    stateful = true,
    conversationInput = [],
  } = options || {};

  const normalizedEffort = effort === "xhigh" ? "high" : (effort === "none" ? "low" : effort);
  const writeTools = Array.isArray(toolsUsed)
    ? toolsUsed
      .map((item) => (typeof item === "string" ? item : item?.tool))
      .filter((name) => INSTRUCTION_VERSION_AUTOSAVE_WRITE_TOOLS.has(name))
    : [];

  const toolSummary = writeTools.length > 0
    ? writeTools.slice(-10).join(", ")
    : "ไม่ระบุ";
  const changeCount = Array.isArray(changes) ? changes.length : 0;
  const finalSummary = typeof finalContent === "string" && finalContent.trim()
    ? finalContent.trim().substring(0, 280)
    : "";

  const promptInput = [
    {
      role: "user",
      content: [
        {
          type: "input_text",
          text: [
            "งาน: เขียน note สั้นสำหรับบันทึกเวอร์ชันของ instruction หลังจากแก้ไขเสร็จแล้ว",
            "ข้อกำหนด:",
            "- ตอบเป็นข้อความบรรทัดเดียวเท่านั้น",
            "- ความยาวประมาณ 12-120 ตัวอักษร",
            "- สรุปเฉพาะสิ่งที่แก้จริงในรอบนี้",
            "- ห้ามใส่ markdown, quote, prefix พิเศษ",
            "",
            `จำนวนการแก้ไข: ${changeCount}`,
            `เครื่องมือที่ใช้แก้ไข: ${toolSummary}`,
            finalSummary ? `สรุปคำตอบล่าสุด: ${finalSummary}` : "",
            "",
            "ตอบเฉพาะ note พร้อมใช้ได้ทันที",
          ].filter(Boolean).join("\n"),
        },
      ],
    },
  ];

  const payload = {
    model,
    tools: [],
    reasoning: { effort: normalizedEffort },
    input:
      stateful || !Array.isArray(conversationInput) || conversationInput.length === 0
        ? promptInput
        : [...conversationInput, ...promptInput],
  };
  if (stateful && previousResponseId) {
    payload.previous_response_id = previousResponseId;
  }

  const response = await openai.responses.create(payload);
  const rawNote = extractInstructionResponseText(response);
  const note = sanitizeInstructionVersionNote(rawNote);

  return {
    responseId: response?.id || null,
    usage: mapInstructionResponseUsage(response?.usage),
    note,
  };
}

function mapInstructionToolsForResponses(tools) {
  if (!Array.isArray(tools)) return [];
  return tools
    .map((tool) => {
      if (tool?.type === "function" && tool.function) {
        return {
          type: "function",
          name: tool.function.name,
          description: tool.function.description,
          parameters: tool.function.parameters || { type: "object", properties: {} },
        };
      }
      return tool;
    })
    .filter(Boolean);
}

function normalizeInstructionHistoryForResponses(history) {
  const safeHistory = Array.isArray(history) ? history : [];
  const normalized = [];
  for (const msg of safeHistory) {
    if (!msg || typeof msg !== "object") continue;
    if (!["system", "developer", "user", "assistant"].includes(msg.role)) continue;
    if (typeof msg.content === "string") {
      const content = msg.content.trim();
      if (!content) continue;
      normalized.push({ role: msg.role, content });
    } else if (Array.isArray(msg.content) && msg.content.length > 0) {
      normalized.push({ role: msg.role, content: msg.content });
    }
  }
  return normalized;
}

function buildInstructionUserInputForResponses(message, images) {
  const text = typeof message === "string" ? message.trim() : "";
  const hasImages = Array.isArray(images) && images.length > 0;
  if (!hasImages) return text;

  const content = [];
  if (text) content.push({ type: "input_text", text });

  for (const img of images.slice(0, 10)) {
    if (img?.name) {
      content.push({ type: "input_text", text: `[ไฟล์แนบ: ${img.name}]` });
    }
    const imageUrl = img?.data || img?.imageData || img;
    if (!imageUrl) continue;
    content.push({
      type: "input_image",
      image_url: imageUrl,
      detail: img?.detail || "low",
    });
  }

  return content.length > 0 ? content : [{ type: "input_text", text: "[แนบรูปภาพ]" }];
}

function buildInstructionUserHistoryText(message, images) {
  const text = typeof message === "string" ? message.trim() : "";
  if (text) return text;
  const imageCount = Array.isArray(images) ? images.length : 0;
  if (imageCount > 0) return `[แนบรูปภาพ ${imageCount} รูป]`;
  return "";
}

function mapInstructionResponseUsage(usage) {
  const promptTokens = usage?.input_tokens || 0;
  const completionTokens = usage?.output_tokens || 0;
  const reasoningTokens = usage?.output_tokens_details?.reasoning_tokens || 0;
  const totalTokens = usage?.total_tokens || (promptTokens + completionTokens);
  return {
    prompt_tokens: promptTokens,
    completion_tokens: completionTokens,
    reasoning_tokens: reasoningTokens,
    total_tokens: totalTokens,
  };
}

function addInstructionUsage(totalUsage, usage) {
  if (!usage) return;
  totalUsage.prompt_tokens += usage.prompt_tokens || 0;
  totalUsage.completion_tokens += usage.completion_tokens || 0;
  totalUsage.reasoning_tokens += usage.reasoning_tokens || 0;
  totalUsage.total_tokens += usage.total_tokens || 0;
}

function extractInstructionResponseFunctionCalls(response) {
  const output = Array.isArray(response?.output) ? response.output : [];
  return output.filter((item) =>
    item?.type === "function_call" &&
    typeof item?.name === "string" &&
    typeof item?.call_id === "string"
  );
}

function extractInstructionResponseText(response) {
  if (typeof response?.output_text === "string") return response.output_text;
  const output = Array.isArray(response?.output) ? response.output : [];
  let text = "";
  for (const item of output) {
    if (item?.type !== "message" || !Array.isArray(item.content)) continue;
    for (const part of item.content) {
      if (part?.type === "output_text" && typeof part?.text === "string") {
        text += part.text;
      }
    }
  }
  return text;
}

// Instruction Chat API — Main chat endpoint with tool loop (Responses API)
app.post("/api/instruction-ai", requireAdmin, async (req, res) => {
  try {
    const { instructionId, message = "", model = "gpt-5.2", thinking = "medium", history = [], images } = req.body;
    const hasIncomingImages = Array.isArray(images) && images.length > 0;

    if (!instructionId || (typeof instructionId === "string" && !instructionId.trim())) {
      incrementInstructionMetric("instruction_id_invalid_total");
      console.warn("[InstructionChat] Missing instructionId", {
        instruction_id_invalid_total: INSTRUCTION_METRICS.instruction_id_invalid_total,
      });
      return res.status(400).json({ error: "ต้องเลือก Instruction ก่อน" });
    }
    if (!ObjectId.isValid(instructionId)) {
      incrementInstructionMetric("instruction_id_invalid_total");
      console.warn("[InstructionChat] Invalid instructionId", {
        instructionId,
        instruction_id_invalid_total: INSTRUCTION_METRICS.instruction_id_invalid_total,
      });
      return res.status(400).json({ error: "instructionId ไม่ถูกต้อง" });
    }
    if ((!message || !message.trim()) && !hasIncomingImages) {
      return res.status(400).json({ error: "ต้องพิมพ์ข้อความ" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const apiKeyToUse = await getOpenAIApiKeyForBot(null, null);
    if (!apiKeyToUse.apiKey) {
      return res.json({ error: "ยังไม่พบ OpenAI API Key ในระบบหรือ Environment" });
    }
    const openai = buildLLMClientFromKey(apiKeyToUse);
    if (!openai) {
      return res.json({ error: "ไม่สามารถสร้าง client สำหรับ API key ที่เลือกได้" });
    }
    const resolvedInstructionModel = resolveModelForProvider(
      model,
      apiKeyToUse.provider,
    );
    if (!resolvedInstructionModel.ok) {
      return res.status(400).json({ error: resolvedInstructionModel.error });
    }
    const usePreviousResponseId = canUseInstructionPreviousResponseId(
      apiKeyToUse.provider,
    );
    const chatService = new InstructionChatService(db, openai, {
      resetFollowUpConfigCache,
      invalidateInstructionPromptCaches,
      invalidateAllRuntimeCaches,
    });

    // Get instruction for system prompt
    const instruction = await db.collection("instructions_v2").findOne({ _id: new ObjectId(instructionId) });
    if (!instruction) return res.json({ error: "ไม่พบ Instruction" });

    const dataItemsSummary = chatService.buildDataItemsSummary(instruction);
    const sessionId = `ses_${Date.now().toString(36)}`;
    const systemPrompt = buildInstructionChatSystemPrompt(instructionId, instruction, dataItemsSummary);

    const safeHistory = normalizeInstructionHistoryForResponses(history);
    const lastHistoryMsg = safeHistory[safeHistory.length - 1];
    const isDuplicatedUserMessage =
      !hasIncomingImages &&
      lastHistoryMsg &&
      lastHistoryMsg.role === "user" &&
      typeof lastHistoryMsg.content === "string" &&
      lastHistoryMsg.content.trim() === String(message).trim();

    const tools = mapInstructionToolsForResponses(chatService.getToolDefinitions());
    const effort = resolveInstructionReasoningEffort(model, thinking);

    let nextInput = [{ role: "system", content: systemPrompt }, ...safeHistory];
    if (!isDuplicatedUserMessage) {
      nextInput.push({ role: "user", content: buildInstructionUserInputForResponses(message, images) });
    }
    const statelessInput = [...nextInput];

    const toolsUsed = [];
    const changes = [];
    let versionSnapshot = null;
    let unsavedWriteChanges = 0;
    let totalUsage = { prompt_tokens: 0, completion_tokens: 0, reasoning_tokens: 0, total_tokens: 0 };
    let finalContent = "";
    let previousResponseId = null;

    for (let i = 0; i < INSTRUCTION_MAX_TOOL_ITERATIONS; i++) {
      const payload = {
        model: resolvedInstructionModel.model,
        input: usePreviousResponseId ? nextInput : statelessInput,
        tools,
        tool_choice: "auto",
        reasoning: { effort },
      };
      if (usePreviousResponseId && previousResponseId) {
        payload.previous_response_id = previousResponseId;
      }

      const response = await openai.responses.create(payload);
      if (usePreviousResponseId) {
        previousResponseId = response.id;
      }
      addInstructionUsage(totalUsage, mapInstructionResponseUsage(response.usage));

      const toolCalls = extractInstructionResponseFunctionCalls(response);
      if (toolCalls.length === 0) {
        finalContent = extractInstructionResponseText(response);
        break;
      }

      const toolOutputs = [];
      for (const toolCall of toolCalls) {
        const toolName = toolCall.name;
        let args = {};
        try { args = JSON.parse(toolCall.arguments || "{}"); } catch (e) { }

        const result = await chatService.executeTool(toolName, args, instructionId, sessionId);
        if (toolName === "save_version" && result?.success && Number.isInteger(result?.version)) {
          versionSnapshot = {
            auto: false,
            version: result.version,
            note: result.note || "",
            snapshotAt: result.snapshotAt || null,
          };
          unsavedWriteChanges = 0;
        }

        toolsUsed.push({
          tool: toolName,
          args,
          resultCount: result.results?.length || result.totalMatches || undefined,
          summary: buildToolSummary(toolName, result),
        });
        if (result.changeId) {
          changes.push({ changeId: result.changeId, tool: toolName });
          unsavedWriteChanges += 1;
        }

        toolOutputs.push({
          type: "function_call_output",
          call_id: toolCall.call_id,
          output: JSON.stringify(result),
        });
      }

      if (usePreviousResponseId) {
        nextInput = toolOutputs;
      } else {
        appendInstructionTurnToStatelessInput(statelessInput, {
          assistantText: extractInstructionResponseText(response),
          toolCalls,
          toolOutputs,
        });
      }
    }

    if (!finalContent || !finalContent.trim()) {
      try {
        const forcedSummary = await requestInstructionFinalSummaryWithoutTools(openai, {
          model: resolvedInstructionModel.model,
          previousResponseId,
          effort,
          toolsUsed,
          stateful: usePreviousResponseId,
          conversationInput: statelessInput,
        });
        if (usePreviousResponseId && forcedSummary.responseId) {
          previousResponseId = forcedSummary.responseId;
        }
        addInstructionUsage(totalUsage, forcedSummary.usage);
        if (forcedSummary.content) finalContent = forcedSummary.content;
      } catch (forcedSummaryError) {
        console.warn("[InstructionChat] Forced summary failed:", forcedSummaryError.message);
      }
    }

    if (!finalContent || !finalContent.trim()) {
      finalContent = getInstructionFinalTextFallback(toolsUsed);
    }

    const shouldAutoSaveVersion = unsavedWriteChanges > 0;
    if (shouldAutoSaveVersion) {
      let autoNote = "";
      try {
        const noteResult = await generateInstructionVersionNoteWithModel(openai, {
          model: resolvedInstructionModel.model,
          previousResponseId,
          effort,
          toolsUsed,
          changes,
          finalContent,
          stateful: usePreviousResponseId,
          conversationInput: statelessInput,
        });
        if (usePreviousResponseId && noteResult?.responseId) {
          previousResponseId = noteResult.responseId;
        }
        addInstructionUsage(totalUsage, noteResult?.usage);
        autoNote = sanitizeInstructionVersionNote(noteResult?.note || "");
      } catch (noteError) {
        console.warn("[InstructionChat] Version note generation failed:", noteError?.message || noteError);
      }
      if (!autoNote) {
        autoNote = buildInstructionAutoVersionFallbackNote(toolsUsed, changes);
      }
      try {
        const autoVersion = await chatService.save_version(
          instructionId,
          { note: autoNote },
          sessionId,
        );
        if (!autoVersion?.error && autoVersion?.success && Number.isInteger(autoVersion?.version)) {
          versionSnapshot = {
            auto: true,
            version: autoVersion.version,
            note: autoVersion.note || autoNote,
            snapshotAt: autoVersion.snapshotAt || null,
          };
          toolsUsed.push({
            tool: "save_version",
            args: { note: autoNote },
            summary: buildToolSummary("save_version", autoVersion),
          });
        } else {
          versionSnapshot = {
            auto: true,
            error: autoVersion?.error || "save_version_failed",
            note: autoNote,
          };
        }
      } catch (autoVersionError) {
        console.error("[InstructionChat] Auto save_version error:", autoVersionError);
        versionSnapshot = {
          auto: true,
          error: autoVersionError?.message || "save_version_failed",
          note: autoNote,
        };
      }
    }

    res.json({
      content: finalContent,
      toolsUsed,
      changes,
      usage: totalUsage,
      versionSnapshot,
      model: resolvedInstructionModel.model,
      thinking,
    });

  } catch (error) {
    console.error("[InstructionChat] API Error:", error);
    res.json({ error: "เกิดข้อผิดพลาดในการประมวลผล: " + error.message });
  }
});

