// Undo API
app.post("/api/instruction-ai/undo/:changeId", requireAdmin, async (req, res) => {
  try {
    const client = await connectDB();
    const db = client.db("chatbot");
    const changeLog = await db.collection("instruction_chat_changelog").findOne({ changeId: req.params.changeId, undone: false });
    if (!changeLog) return res.json({ error: "ไม่พบหรือยกเลิกแล้ว" });

    const apiKeyToUse = await getOpenAIApiKeyForBot(null, null);
    const openaiClient = buildLLMClientFromKey(apiKeyToUse);
    const chatService = new InstructionChatService(db, openaiClient, {
      resetFollowUpConfigCache,
      invalidateInstructionPromptCaches,
      invalidateAllRuntimeCaches,
    });
    let instructionMutated = false;

    // Reverse the operation
    if (changeLog.tool === "update_cell" && changeLog.before) {
      const undoResult = await chatService.update_cell(changeLog.instructionId, {
        itemId: changeLog.params.itemId,
        rowIndex: changeLog.params.rowIndex,
        column: changeLog.params.column,
        newValue: changeLog.before.value,
      }, "undo");
      if (undoResult?.error) return res.json({ error: undoResult.error });
      instructionMutated = true;
    } else if (changeLog.tool === "add_row" && changeLog.after) {
      const undoResult = await chatService.delete_row(changeLog.instructionId, {
        itemId: changeLog.params.itemId,
        rowIndex: changeLog.after.rowIndex,
      }, "undo");
      if (undoResult?.error) return res.json({ error: undoResult.error });
      instructionMutated = true;
    } else if (changeLog.tool === "delete_row" && changeLog.before) {
      const undoResult = await chatService.add_row(changeLog.instructionId, {
        itemId: changeLog.params.itemId,
        rowData: changeLog.before.rowData,
        position: "after",
        afterRowIndex: Math.max(0, changeLog.params.rowIndex - 1),
      }, "undo");
      if (undoResult?.error) return res.json({ error: undoResult.error });
      instructionMutated = true;
    } else if (changeLog.tool === "update_text_content" && changeLog.before) {
      const inst = await db.collection("instructions_v2").findOne({ _id: new ObjectId(changeLog.instructionId) });
      if (inst) {
        const itemIndex = (inst.dataItems || []).findIndex(i => i.itemId === changeLog.params.itemId);
        if (itemIndex !== -1) {
          const updateResult = await db.collection("instructions_v2").updateOne(
            { _id: new ObjectId(changeLog.instructionId) },
            {
              $set: {
                [`dataItems.${itemIndex}.content`]: changeLog.before.content,
                [`dataItems.${itemIndex}.updatedAt`]: new Date(),
                updatedAt: new Date(),
              },
            }
          );
          if (updateResult.matchedCount > 0) instructionMutated = true;
        }
      }
    } else if (changeLog.tool === "update_rows_bulk" && changeLog.before?.changes) {
      // Reverse each cell update
      for (const c of changeLog.before.changes) {
        const undoResult = await chatService.update_cell(changeLog.instructionId, {
          itemId: changeLog.params.itemId,
          rowIndex: c.rowIndex,
          column: c.column,
          newValue: c.value,
        }, "undo");
        if (undoResult?.error) return res.json({ error: undoResult.error });
        instructionMutated = true;
      }
    } else if (changeLog.tool === "add_column" && changeLog.after) {
      // Remove the added column
      const inst = await db.collection("instructions_v2").findOne({ _id: new ObjectId(changeLog.instructionId) });
      if (inst) {
        const itemIndex = (inst.dataItems || []).findIndex(i => i.itemId === changeLog.params.itemId);
        if (itemIndex !== -1) {
          const item = inst.dataItems[itemIndex];
          const cols = item.data?.columns || [];
          const rows = item.data?.rows || [];
          const ci = cols.indexOf(changeLog.params.columnName);
          if (ci !== -1) {
            cols.splice(ci, 1);
            rows.forEach(row => { if (Array.isArray(row)) row.splice(ci, 1); });
            const updateResult = await db.collection("instructions_v2").updateOne(
              { _id: new ObjectId(changeLog.instructionId) },
              {
                $set: {
                  [`dataItems.${itemIndex}.data`]: { columns: cols, rows },
                  [`dataItems.${itemIndex}.updatedAt`]: new Date(),
                  updatedAt: new Date(),
                },
              }
            );
            if (updateResult.matchedCount > 0) instructionMutated = true;
          }
        }
      }
    } else if (changeLog.tool === "delete_rows_bulk" && changeLog.before?.deletedRows) {
      // Re-insert deleted rows at original positions (ascending order)
      const sorted = [...changeLog.before.deletedRows].sort((a, b) => a.rowIndex - b.rowIndex);
      const inst = await db.collection("instructions_v2").findOne({ _id: new ObjectId(changeLog.instructionId) });
      if (inst) {
        const itemIndex = (inst.dataItems || []).findIndex(i => i.itemId === changeLog.params.itemId);
        if (itemIndex !== -1) {
          const item = inst.dataItems[itemIndex];
          const cols = item.data?.columns || [];
          const rows = item.data?.rows || [];
          for (const deleted of sorted) {
            const rowArr = cols.map(c => deleted[c] !== undefined ? String(deleted[c]) : "");
            const idx = Math.min(deleted.rowIndex, rows.length);
            rows.splice(idx, 0, rowArr);
          }
          const updateResult = await db.collection("instructions_v2").updateOne(
            { _id: new ObjectId(changeLog.instructionId) },
            {
              $set: {
                [`dataItems.${itemIndex}.data.rows`]: rows,
                [`dataItems.${itemIndex}.updatedAt`]: new Date(),
                updatedAt: new Date(),
              },
            }
          );
          if (updateResult.matchedCount > 0) instructionMutated = true;
        }
      }
    }

    await db.collection("instruction_chat_changelog").updateOne(
      { changeId: req.params.changeId },
      { $set: { undone: true, undoneAt: new Date() } }
    );
    if (instructionMutated) {
      invalidateInstructionPromptCaches();
    }

    res.json({ success: true, message: "ยกเลิกการแก้ไขเรียบร้อย" });
  } catch (error) {
    res.json({ error: error.message });
  }
});

// ─── Helper: Build meaningful tool result summary ───
function buildToolSummary(toolName, result) {
  if (result.error) return `❌ ${result.error}`;

  switch (toolName) {
    case 'get_instruction_overview':
      return `📋 ${result.name || 'Instruction'} — ${result.dataItems?.length || 0} data items`;

    case 'search_in_table':
    case 'search_content':
      return `🔍 พบ ${result.totalMatches || result.results?.length || 0} ผลลัพธ์`;

    case 'get_rows': {
      const rows = result.rows?.length || 0;
      const total = result.totalRows || rows;
      return `📊 แสดง ${rows} แถว (จาก ${total} ทั้งหมด)`;
    }

    case 'get_text_content':
      return `📝 ข้อความ ${result.content ? `${result.content.length} ตัวอักษร` : 'ว่าง'}`;

    case 'get_data_item_detail': {
      const type = result.type || 'unknown';
      if (type === 'table') {
        return `📊 ตาราง: ${result.columns?.length || 0} คอลัมน์, ${result.totalRows || 0} แถว`;
      }
      return `📝 ${type}: ${result.content ? `${result.content.length} ตัวอักษร` : 'loaded'}`;
    }

    case 'update_cell':
      return `✏️ แก้ไขเซลล์สำเร็จ`;

    case 'update_rows_bulk':
      return `✏️ แก้ไข ${result.updatedCount || 0} แถว`;

    case 'add_row':
      return `➕ เพิ่มแถวสำเร็จ`;

    case 'create_table_item':
      return `📊 สร้างตาราง "${result.title || ''}" (${result.columns?.length || 0} คอลัมน์, ${result.totalRows || 0} แถว)`;

    case 'create_text_item':
      return `📝 สร้างข้อความ "${result.title || ''}" (${result.contentLength || 0} ตัวอักษร)`;

    case 'delete_row':
      return `🗑️ ลบแถวสำเร็จ`;

    case 'delete_rows_bulk':
      return `🗑️ ลบ ${result.deletedCount || 0} แถว`;

    case 'delete_rows_bulk_confirm':
      return `⚠️ ยืนยันลบ ${result.count || 0} แถว — ต้องใช้ confirmToken`;

    case 'delete_column':
      return `🗑️ ลบคอลัมน์ "${result.deletedColumn || ''}" สำเร็จ (เหลือ ${result.newColumnCount || 0} คอลัมน์)`;

    case 'delete_data_item':
      if (result.requireConfirm) return `⚠️ ยืนยันลบชุดข้อมูล "${result.title || ''}" — ต้องส่ง confirmTitle`;
      return `🗑️ ลบชุดข้อมูล "${result.deletedTitle || ''}" สำเร็จ`;

    case 'update_text_content':
      return `✏️ อัปเดตข้อความสำเร็จ`;

    // Conversation Starter tools
    case 'get_conversation_starter':
      return `🚀 Starter: ${result.enabled ? 'เปิด' : 'ปิด'} (${result.messageCount || result.messages?.length || 0} รายการ)`;
    case 'set_conversation_starter_enabled':
      return `🚀 Starter ${result.enabled ? 'เปิดใช้งาน' : 'ปิดใช้งาน'}แล้ว`;
    case 'add_conversation_starter_message':
      return `➕ เพิ่มข้อความเริ่มต้นแล้ว (รวม ${result.messageCount || result.messages?.length || 0} รายการ)`;
    case 'update_conversation_starter_message':
      return `✏️ แก้ไขข้อความเริ่มต้น ${result.messageId || ''} สำเร็จ`;
    case 'remove_conversation_starter_message':
      return `🗑️ ลบข้อความเริ่มต้นแล้ว (เหลือ ${result.messageCount || result.messages?.length || 0} รายการ)`;
    case 'reorder_conversation_starter_message':
      return `↕️ จัดลำดับข้อความเริ่มต้นสำเร็จ`;

    // Follow-Up tools
    case 'get_followup_config':
      return `⚙️ การตั้งค่าติดตาม: ${result.autoFollowUpEnabled ? 'เปิด' : 'ปิด'}, ${result.totalRounds || 0} rounds`;
    case 'get_followup_round_detail':
      return `📋 Round ${result.roundIndex ?? '?'}: ${(result.message || '').substring(0, 40)}...`;
    case 'update_followup_settings':
      return `⚙️ อัปเดตการตั้งค่าติดตาม: ${result.updated?.map(u => u.field).join(', ') || ''}`;
    case 'update_followup_round':
      return `✏️ แก้ไข Round ${result.roundIndex ?? '?'} สำเร็จ`;
    case 'manage_followup_images':
      return `🖼️ ${result.action === 'add' ? 'เพิ่ม' : 'ลบ'}รูปใน Round ${result.roundIndex ?? '?'} (${result.currentImageCount || 0} รูป)`;
    case 'list_followup_pages':
      return `📋 พบ ${result.totalPages || 0} เพจ`;
    case 'update_page_model':
      return `🤖 เปลี่ยนโมเดลเป็น ${result.model || '?'} (${result.results?.length || 0} เพจ)`;
    case 'list_followup_assets':
      return `🖼️ พบ ${result.totalAssets || 0} รูปภาพ`;

    // Version tools
    case 'list_versions':
      return `🕘 พบเวอร์ชัน ${result.totalVersions || result.versions?.length || 0} รายการ`;
    case 'view_version_detail':
      return `🧾 เวอร์ชัน ${result.version || "?"} (${result.dataItems?.length || 0} data items)`;
    case 'compare_version_stats':
      return `📈 เปรียบเทียบ v${result.version1?.version ?? "?"} ↔ v${result.version2?.version ?? "?"}`;
    case 'save_version':
      return result.message || `💾 บันทึกเวอร์ชัน ${result.version || "?"} แล้ว`;

    default:
      return result.success ? '✅ สำเร็จ' : '📦 เสร็จสิ้น';
  }
}

const INSTRUCTION_VERSION_AUTOSAVE_WRITE_TOOLS = new Set([
  "update_cell",
  "update_rows_bulk",
  "add_row",
  "delete_row",
  "update_text_content",
  "add_column",
  "delete_column",
  "delete_rows_bulk",
  "delete_data_item",
  "create_table_item",
  "create_text_item",
  "set_conversation_starter_enabled",
  "add_conversation_starter_message",
  "update_conversation_starter_message",
  "remove_conversation_starter_message",
  "reorder_conversation_starter_message",
]);

function buildInstructionAutoVersionFallbackNote(toolsUsed = [], changes = []) {
  const names = Array.isArray(toolsUsed)
    ? toolsUsed
      .map((item) => (typeof item === "string" ? item : item?.tool))
      .filter((name) => INSTRUCTION_VERSION_AUTOSAVE_WRITE_TOOLS.has(name))
    : [];

  const counts = new Map();
  names.forEach((name) => {
    counts.set(name, (counts.get(name) || 0) + 1);
  });

  const topSummaries = Array.from(counts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3)
    .map(([name, count]) => `${name} x${count}`);
  const extraToolKinds = Math.max(0, counts.size - topSummaries.length);
  const changeCount = Array.isArray(changes) ? changes.length : 0;

  const summaryText = topSummaries.length > 0
    ? topSummaries.join(", ")
    : "instruction updated";
  const extraText = extraToolKinds > 0 ? ` +${extraToolKinds} tools` : "";
  const note = `ปรับ instruction (${changeCount} จุด): ${summaryText}${extraText}`;
  return note.substring(0, 180);
}

