// ============================ OpenAI API Key Management ============================

// Model pricing (USD per 1M tokens) - OpenAI Standard tier prices (Dec 2024)
const OPENAI_MODEL_PRICING = {
  // GPT-5 series
  "gpt-5": { input: 1.25, output: 10.0 },
  "gpt-5.1": { input: 1.25, output: 10.0 },
  "gpt-5.2": { input: 1.75, output: 14.0 },
  "gpt-5.2-codex": { input: 1.75, output: 14.0 },
  "gpt-5-mini": { input: 0.25, output: 2.0 },
  "gpt-5-nano": { input: 0.05, output: 0.4 },
  "gpt-5-pro": { input: 15.0, output: 120.0 },
  // GPT-4.1 series
  "gpt-4.1": { input: 2.0, output: 8.0 },
  "gpt-4.1-mini": { input: 0.4, output: 1.6 },
  "gpt-4.1-nano": { input: 0.1, output: 0.4 },
  // GPT-4o series
  "gpt-4o": { input: 2.5, output: 10.0 },
  "gpt-4o-mini": { input: 0.15, output: 0.6 },
  // O-series reasoning models
  "o1": { input: 15.0, output: 60.0 },
  "o1-mini": { input: 1.1, output: 4.4 },
  "o1-pro": { input: 150.0, output: 600.0 },
  "o3": { input: 2.0, output: 8.0 },
  "o3-mini": { input: 1.1, output: 4.4 },
  "o3-pro": { input: 20.0, output: 80.0 },
  "o4-mini": { input: 1.1, output: 4.4 },
  // Legacy models
  "gpt-4-turbo": { input: 10.0, output: 30.0 },
  "gpt-3.5-turbo": { input: 0.5, output: 1.5 },
  // Default fallback
  "default": { input: 1.0, output: 4.0 },
};

// Helper: Calculate estimated cost
function calculateOpenAICost(model, promptTokens, completionTokens) {
  const pricing = OPENAI_MODEL_PRICING[model] || OPENAI_MODEL_PRICING["default"];
  const inputCost = (promptTokens / 1000000) * pricing.input;
  const outputCost = (completionTokens / 1000000) * pricing.output;
  return inputCost + outputCost;
}

// Helper: Mask API key for display
function maskApiKey(apiKey) {
  if (!apiKey || apiKey.length < 10) return "sk-***";
  return apiKey.substring(0, 7) + "..." + apiKey.substring(apiKey.length - 4);
}

// Helper: Get API key for a bot (with fallback to default key or env var)
async function getOpenAIApiKeyForBot(botId, platform) {
  const normalizeKeyPayload = (
    apiKey,
    keyId = null,
    keyName = null,
    provider = LLM_PROVIDER_OPENAI,
  ) => ({
    apiKey: apiKey || null,
    key: apiKey || null, // backward compatibility for legacy call sites
    keyId: keyId || null,
    id: keyId || null, // backward compatibility for legacy call sites
    keyName: keyName || null,
    name: keyName || null, // backward compatibility for legacy call sites
    provider: normalizeProvider(provider),
  });

  try {
    const runtimeKey = buildBotRuntimeCacheKey(platform, botId);
    if (runtimeOpenAIKeyCache.has(runtimeKey)) {
      return runtimeOpenAIKeyCache.get(runtimeKey);
    }

    const client = await connectDB();
    const db = client.db("chatbot");

    // First, check if bot has a specific key assigned
    const botSnapshot = botId
      ? await getBotRuntimeSnapshot(botId, platform)
      : null;

    if (botSnapshot?.openaiApiKeyId) {
      const keyDoc = await db.collection("openai_api_keys").findOne({
        _id: new ObjectId(botSnapshot.openaiApiKeyId),
        isActive: true,
      });
      if (keyDoc && keyDoc.apiKey) {
        const payload = normalizeKeyPayload(
          keyDoc.apiKey,
          keyDoc._id.toString(),
          keyDoc.name,
          keyDoc.provider,
        );
        runtimeOpenAIKeyCache.set(runtimeKey, payload);
        return payload;
      }
    }

    // Fallback to default key
    const defaultKey = await db.collection("openai_api_keys").findOne({
      isDefault: true,
      isActive: true,
    });
    if (defaultKey && defaultKey.apiKey) {
      const payload = normalizeKeyPayload(
        defaultKey.apiKey,
        defaultKey._id.toString(),
        defaultKey.name,
        defaultKey.provider,
      );
      runtimeOpenAIKeyCache.set(runtimeKey, payload);
      return payload;
    }

    // Fallback to any active key
    const anyKey = await db.collection("openai_api_keys").findOne({
      isActive: true,
    });
    if (anyKey && anyKey.apiKey) {
      const payload = normalizeKeyPayload(
        anyKey.apiKey,
        anyKey._id.toString(),
        anyKey.name,
        anyKey.provider,
      );
      runtimeOpenAIKeyCache.set(runtimeKey, payload);
      return payload;
    }

    // Final fallback to environment variable
    if (OPENAI_API_KEY) {
      const payload = normalizeKeyPayload(
        OPENAI_API_KEY,
        null,
        "Environment Variable",
        LLM_PROVIDER_OPENAI,
      );
      runtimeOpenAIKeyCache.set(runtimeKey, payload);
      return payload;
    }

    const emptyPayload = normalizeKeyPayload(null, null, null);
    runtimeOpenAIKeyCache.set(runtimeKey, emptyPayload);
    return emptyPayload;
  } catch (err) {
    console.error("[OpenAI Keys] Error getting API key for bot:", err);
    return normalizeKeyPayload(
      OPENAI_API_KEY || null,
      null,
      OPENAI_API_KEY ? "Environment Variable (fallback)" : null,
      LLM_PROVIDER_OPENAI,
    );
  }
}

// Helper: Log OpenAI API usage
async function logOpenAIUsage(data) {
  try {
    const {
      apiKeyId, botId, platform, model, provider,
      promptTokens, completionTokens, totalTokens,
      functionName
    } = data;

    const client = await connectDB();
    const db = client.db("chatbot");

    const normalizedProvider = normalizeProvider(provider);
    const estimatedCost =
      normalizedProvider === LLM_PROVIDER_OPENROUTER
        ? null
        : calculateOpenAICost(model, promptTokens || 0, completionTokens || 0);

    await db.collection("openai_usage_logs").insertOne({
      apiKeyId: apiKeyId ? new ObjectId(apiKeyId) : null,
      botId: botId || null,
      platform: platform || null,
      provider: normalizedProvider,
      model: model || "unknown",
      promptTokens: promptTokens || 0,
      completionTokens: completionTokens || 0,
      totalTokens: totalTokens || 0,
      estimatedCost,
      functionName: functionName || null,
      timestamp: new Date(),
    });

    // Update usage count on API key
    if (apiKeyId) {
      await db.collection("openai_api_keys").updateOne(
        { _id: new ObjectId(apiKeyId) },
        {
          $inc: { usageCount: 1 },
          $set: { lastUsedAt: new Date() }
        }
      );
    }
  } catch (err) {
    console.error("[OpenAI Usage] Error logging usage:", err);
  }
}

// GET: List all API keys (masked)
app.get("/api/openai-keys", async (req, res) => {
  try {
    const client = await connectDB();
    const db = client.db("chatbot");
    const keys = await db.collection("openai_api_keys")
      .find({})
      .sort({ createdAt: -1 })
      .toArray();

    const maskedKeys = keys.map(key => ({
      id: key._id.toString(),
      name: key.name,
      provider: normalizeProvider(key.provider),
      maskedKey: key.maskedKey || maskApiKey(key.apiKey),
      isActive: key.isActive !== false,
      isDefault: key.isDefault === true,
      usageCount: key.usageCount || 0,
      lastUsedAt: key.lastUsedAt || null,
      createdAt: key.createdAt,
      updatedAt: key.updatedAt,
    }));

    res.json({ success: true, keys: maskedKeys });
  } catch (err) {
    console.error("[OpenAI Keys] Error listing keys:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

// POST: Create new API key
app.post("/api/openai-keys", async (req, res) => {
  try {
    const { name, apiKey, isDefault, provider } = req.body;
    const normalizedProvider = normalizeProvider(provider);

    if (!name || !name.trim()) {
      return res.status(400).json({ success: false, error: "กรุณาระบุชื่อ API Key" });
    }
    if (!apiKey || !apiKey.trim()) {
      return res.status(400).json({ success: false, error: "กรุณาระบุ API Key" });
    }
    if (!validateApiKeyForProvider(apiKey, normalizedProvider)) {
      return res.status(400).json({
        success: false,
        error: getApiKeyFormatHint(normalizedProvider),
      });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("openai_api_keys");

    // If setting as default, unset other defaults
    if (isDefault) {
      await coll.updateMany({}, { $set: { isDefault: false } });
    }

    const now = new Date();
    const keyDoc = {
      name: name.trim(),
      apiKey: apiKey.trim(),
      provider: normalizedProvider,
      maskedKey: maskApiKey(apiKey.trim()),
      isActive: true,
      isDefault: isDefault === true,
      usageCount: 0,
      lastUsedAt: null,
      createdAt: now,
      updatedAt: now,
    };

    const result = await coll.insertOne(keyDoc);

    invalidateAllRuntimeCaches();

    res.json({
      success: true,
      key: {
        id: result.insertedId.toString(),
        name: keyDoc.name,
        provider: keyDoc.provider,
        maskedKey: keyDoc.maskedKey,
        isActive: keyDoc.isActive,
        isDefault: keyDoc.isDefault,
        createdAt: keyDoc.createdAt,
      }
    });
  } catch (err) {
    console.error("[OpenAI Keys] Error creating key:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

// PUT: Update API key
app.put("/api/openai-keys/:id", async (req, res) => {
  try {
    const { id } = req.params;
    const { name, apiKey, isActive, isDefault, provider } = req.body;

    if (!ObjectId.isValid(id)) {
      return res.status(400).json({ success: false, error: "รหัส API Key ไม่ถูกต้อง" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("openai_api_keys");

    const existing = await coll.findOne({ _id: new ObjectId(id) });
    if (!existing) {
      return res.status(404).json({ success: false, error: "ไม่พบ API Key" });
    }

    const updateData = { updatedAt: new Date() };
    const nextProvider =
      provider !== undefined
        ? normalizeProvider(provider)
        : normalizeProvider(existing.provider);

    if (name !== undefined) updateData.name = name.trim();
    if (isActive !== undefined) updateData.isActive = isActive;
    if (provider !== undefined) {
      updateData.provider = nextProvider;
    } else if (!existing.provider) {
      updateData.provider = nextProvider;
    }

    const normalizedApiKey =
      typeof apiKey === "string" && apiKey.trim() ? apiKey.trim() : "";
    const isApiKeyChanged =
      normalizedApiKey && normalizedApiKey !== existing.maskedKey;

    if (isApiKeyChanged) {
      if (!validateApiKeyForProvider(normalizedApiKey, nextProvider)) {
        return res.status(400).json({
          success: false,
          error: getApiKeyFormatHint(nextProvider),
        });
      }
      updateData.apiKey = normalizedApiKey;
      updateData.maskedKey = maskApiKey(normalizedApiKey);
    } else if (provider !== undefined) {
      if (!validateApiKeyForProvider(existing.apiKey, nextProvider)) {
        return res.status(400).json({
          success: false,
          error:
            "Provider ใหม่ไม่ตรงกับรูปแบบ key ปัจจุบัน กรุณากรอก API Key ใหม่ให้ตรง provider",
        });
      }
    }

    if (isDefault === true) {
      await coll.updateMany({ _id: { $ne: new ObjectId(id) } }, { $set: { isDefault: false } });
      updateData.isDefault = true;
    } else if (isDefault === false) {
      updateData.isDefault = false;
    }

    await coll.updateOne({ _id: new ObjectId(id) }, { $set: updateData });

    const updated = await coll.findOne({ _id: new ObjectId(id) });
    invalidateAllRuntimeCaches();

    res.json({
      success: true,
      key: {
        id: updated._id.toString(),
        name: updated.name,
        provider: normalizeProvider(updated.provider),
        maskedKey: updated.maskedKey,
        isActive: updated.isActive,
        isDefault: updated.isDefault,
        usageCount: updated.usageCount,
        lastUsedAt: updated.lastUsedAt,
        updatedAt: updated.updatedAt,
      }
    });
  } catch (err) {
    console.error("[OpenAI Keys] Error updating key:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

// DELETE: Delete API key
app.delete("/api/openai-keys/:id", async (req, res) => {
  try {
    const { id } = req.params;

    if (!ObjectId.isValid(id)) {
      return res.status(400).json({ success: false, error: "รหัส API Key ไม่ถูกต้อง" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("openai_api_keys");

    const result = await coll.deleteOne({ _id: new ObjectId(id) });

    if (result.deletedCount === 0) {
      return res.status(404).json({ success: false, error: "ไม่พบ API Key" });
    }

    // Remove references from bots
    await db.collection("line_bots").updateMany(
      { openaiApiKeyId: id },
      { $unset: { openaiApiKeyId: "" } }
    );
    await db.collection("facebook_bots").updateMany(
      { openaiApiKeyId: id },
      { $unset: { openaiApiKeyId: "" } }
    );
    await db.collection("instagram_bots").updateMany(
      { openaiApiKeyId: id },
      { $unset: { openaiApiKeyId: "" } }
    );
    await db.collection("whatsapp_bots").updateMany(
      { openaiApiKeyId: id },
      { $unset: { openaiApiKeyId: "" } }
    );

    invalidateAllRuntimeCaches();

    res.json({ success: true, message: "ลบ API Key เรียบร้อยแล้ว" });
  } catch (err) {
    console.error("[OpenAI Keys] Error deleting key:", err);
    res.status(500).json({ success: false, error: err.message });
  }
});

