app.post("/admin/shipping-carriers", async (req, res) => {
  try {
    const { name, trackingUrl } = req.body || {};
    if (!name || typeof name !== "string" || !name.trim()) {
      return res
        .status(400)
        .json({ success: false, error: "กรุณาระบุชื่อขนส่ง" });
    }

    const sanitizedName = name.trim().slice(0, 100);
    const sanitizedUrl =
      typeof trackingUrl === "string" ? trackingUrl.trim().slice(0, 500) : "";

    const escapedName = sanitizedName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("shipping_carriers");
    const existing = await coll.findOne({
      name: { $regex: new RegExp(`^${escapedName}$`, "i") },
    });
    if (existing) {
      return res
        .status(400)
        .json({ success: false, error: "ชื่อขนส่งนี้มีอยู่แล้ว" });
    }

    const count = await coll.countDocuments();
    const result = await coll.insertOne({
      name: sanitizedName,
      trackingUrl: sanitizedUrl,
      sortOrder: count + 1,
      createdAt: new Date(),
    });

    console.log(`[Carriers] เพิ่มขนส่ง: ${sanitizedName}`);
    res.json({
      success: true,
      carrier: {
        _id: result.insertedId,
        name: sanitizedName,
        trackingUrl: sanitizedUrl,
      },
    });
  } catch (error) {
    console.error("[Carriers] เพิ่มขนส่งไม่สำเร็จ:", error);
    res.status(500).json({ success: false, error: error.message });
  }
});

