app.post("/admin/orders/:orderId/tracking", async (req, res) => {
  try {
    const { orderId } = req.params;
    const { trackingNumber, carrier, notifyCustomer } = req.body || {};

    if (
      !trackingNumber ||
      typeof trackingNumber !== "string" ||
      !trackingNumber.trim()
    ) {
      return res
        .status(400)
        .json({ success: false, error: "กรุณาระบุเลขพัสดุ" });
    }

    if (!ObjectId.isValid(orderId)) {
      return res
        .status(400)
        .json({ success: false, error: "รหัสออเดอร์ไม่ถูกต้อง" });
    }

    const sanitizedTracking = trackingNumber.trim().slice(0, 100);
    const sanitizedCarrier =
      typeof carrier === "string" ? carrier.trim().slice(0, 100) : "";

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("orders");
    const order = await coll.findOne({ _id: new ObjectId(orderId) });

    if (!order) {
      return res.status(404).json({ success: false, error: "ไม่พบออเดอร์" });
    }

    await coll.updateOne(
      { _id: new ObjectId(orderId) },
      {
        $set: {
          trackingNumber: sanitizedTracking,
          trackingCarrier: sanitizedCarrier,
          trackingUpdatedAt: new Date(),
          status: "shipped",
          updatedAt: new Date(),
          "orderData.trackingNumber": sanitizedTracking,
          "orderData.trackingNo": sanitizedTracking,
          "orderData.shippingProvider": sanitizedCarrier,
          "orderData.courier": sanitizedCarrier,
        },
      },
    );

    console.log(
      `[Orders] บันทึกเลขพัสดุ ${sanitizedTracking} (${sanitizedCarrier}) สำหรับออเดอร์ ${orderId}`,
    );

    let notificationSent = false;
    if (notifyCustomer !== false && order.userId) {
      try {
        let trackingUrl = "";
        if (sanitizedCarrier) {
          const escapedCarrier = sanitizedCarrier.replace(
            /[.*+?^${}()|[\]\\]/g,
            "\\$&",
          );
          const carrierDoc = await db.collection("shipping_carriers").findOne({
            name: { $regex: new RegExp(`^${escapedCarrier}$`, "i") },
          });
          if (carrierDoc?.trackingUrl) {
            trackingUrl = carrierDoc.trackingUrl.replace(
              "{tracking}",
              encodeURIComponent(sanitizedTracking),
            );
          }
        }

        const orderCode = order.orderCode || orderId.slice(-8).toUpperCase();
        const recipientName =
          order.orderData?.recipientName || order.orderData?.customerName || "";

        const lines = ["📦 แจ้งเลขพัสดุ", `🔖 ออเดอร์: ${orderCode}`];
        if (recipientName) lines.push(`👤 ผู้รับ: ${recipientName}`);
        if (sanitizedCarrier) lines.push(`🚚 ขนส่ง: ${sanitizedCarrier}`);
        lines.push(`📋 เลขพัสดุ: ${sanitizedTracking}`);
        if (trackingUrl) lines.push(`🔍 ตรวจสอบสถานะ: ${trackingUrl}`);
        lines.push("", "ขอบคุณที่ใช้บริการค่ะ 🙏");

        const trackingMessage = lines.join("\n");

        const lastChat = await db.collection("chat_history").findOne(
          buildChatHistoryUserMatch(order.userId),
          { sort: { timestamp: -1 } },
        );
        const platform = normalizeChatPlatform(
          order.platform || lastChat?.platform || "line",
        );
        const botId = order.botId || lastChat?.botId || null;
        const messageDoc = {
          senderId: order.userId,
          role: "assistant",
          content: trackingMessage,
          timestamp: new Date(),
          source: "tracking_notification",
          platform,
          botId,
        };

        const chatColl = db.collection("chat_history");
        const insertResult = await chatColl.insertOne(messageDoc);
        if (insertResult?.insertedId) {
          messageDoc._id = insertResult.insertedId;
        }

        if (platform === "facebook") {
          if (!botId) {
            throw new Error("ไม่พบ Facebook Bot สำหรับการแจ้งเลขพัสดุ");
          }
          const fbBot = await findBotById(db, "facebook", botId);
          if (!fbBot?.accessToken) {
            throw new Error("ไม่พบ access token ของ Facebook Bot");
          }
          await sendFacebookMessage(order.userId, trackingMessage, fbBot.accessToken, {
            metadata: "tracking_notification",
          });
          notificationSent = true;
        } else if (platform === "instagram") {
          if (!botId) {
            throw new Error("ไม่พบ Instagram Bot สำหรับการแจ้งเลขพัสดุ");
          }
          const igBot = await findBotById(db, "instagram", botId);
          const accessToken = resolveMetaAccessToken(igBot || {});
          const instagramSenderId = resolveInstagramSenderId(igBot || {});
          if (!igBot || !accessToken || !instagramSenderId) {
            throw new Error("ไม่พบข้อมูล Instagram Bot สำหรับการแจ้งเลขพัสดุ");
          }
          await sendInstagramMessage(
            order.userId,
            trackingMessage,
            accessToken,
            instagramSenderId,
            {
              selectedImageCollections: igBot.selectedImageCollections || null,
            },
          );
          notificationSent = true;
        } else if (platform === "whatsapp") {
          if (!botId) {
            throw new Error("ไม่พบ WhatsApp Bot สำหรับการแจ้งเลขพัสดุ");
          }
          const waBot = await findBotById(db, "whatsapp", botId);
          const accessToken = resolveMetaAccessToken(waBot || {});
          const phoneNumberId = resolveWhatsAppPhoneNumberId(waBot || {});
          if (!waBot || !accessToken || !phoneNumberId) {
            throw new Error("ไม่พบข้อมูล WhatsApp Bot สำหรับการแจ้งเลขพัสดุ");
          }
          await sendWhatsAppMessage(
            order.userId,
            trackingMessage,
            accessToken,
            phoneNumberId,
            {
              selectedImageCollections: waBot.selectedImageCollections || null,
            },
          );
          notificationSent = true;
        } else {
          const lineClientForSend = await getLineClientForContext(botId);
          if (!lineClientForSend) {
            throw new Error("ไม่พบ LINE client สำหรับการแจ้งเลขพัสดุ");
          }
          await lineClientForSend.pushMessage(order.userId, {
            type: "text",
            text: normalizeOutgoingText(trackingMessage),
          });
          notificationSent = true;
        }

        if (io) {
          io.to("admin").emit("newMessage", {
            userId: order.userId,
            message: messageDoc,
            sender: "assistant",
            timestamp: messageDoc.timestamp,
          });
        }
      } catch (notifyError) {
        console.warn(
          "[Orders] ส่งเลขพัสดุให้ลูกค้าไม่สำเร็จ:",
          notifyError.message,
        );
      }
    }

    if (io) {
      io.to("admin").emit("orderUpdated", {
        orderId,
        userId: order.userId,
      });
    }

    res.json({
      success: true,
      trackingNumber: sanitizedTracking,
      carrier: sanitizedCarrier,
      notificationSent,
    });
  } catch (error) {
    console.error("[Orders] บันทึกเลขพัสดุไม่สำเร็จ:", error);
    res.status(500).json({ success: false, error: error.message });
  }
});

// API: ลบออเดอร์ (Orders page)
app.delete("/admin/orders/:orderId", async (req, res) => {
  try {
    const { orderId } = req.params;

    if (!ObjectId.isValid(orderId)) {
      return res.status(400).json({ success: false, error: "รหัสออเดอร์ไม่ถูกต้อง" });
    }

    const client = await connectDB();
    const db = client.db("chatbot");
    const coll = db.collection("orders");

    const order = await coll.findOne({ _id: new ObjectId(orderId) });
    if (!order) {
      return res.status(404).json({ success: false, error: "ไม่พบออเดอร์" });
    }

    const result = await coll.deleteOne({ _id: new ObjectId(orderId) });
    if (result.deletedCount === 0) {
      return res.status(500).json({ success: false, error: "ไม่สามารถลบออเดอร์ได้" });
    }

    try {
      if (io) {
        io.to("admin").emit("orderDeleted", {
          orderId,
          userId: order.userId,
        });
      }
    } catch (_) { }

    await maybeAnalyzeFollowUp(order.userId, order.platform, order.botId, {
      forceUpdate: true,
    });

    console.log(`[Orders] ลบออเดอร์สำเร็จ ${orderId}`);
    res.json({
      success: true,
      orderId,
      message: "ลบออเดอร์เรียบร้อยแล้ว",
    });
  } catch (error) {
    console.error("[Orders] ไม่สามารถลบออเดอร์ได้:", error);
    res.status(500).json({ success: false, error: error.message });
  }
});

